import React, { useState, useEffect } from 'react';
import { UserRole } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Properties from './components/Properties';
import Residents from './components/Residents';
import Payments from './components/Payments';
import Complaints from './components/Complaints';
import SuperAdmin from './components/SuperAdmin';

const App: React.FC = () => {
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.OWNER);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [impersonatingOwner, setImpersonatingOwner] = useState<string | null>(null);

  // Responsive sidebar handling
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 1024) setSidebarOpen(false);
      else setSidebarOpen(true);
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const renderContent = () => {
    if (currentRole === UserRole.SUPERADMIN && !impersonatingOwner) {
      return <SuperAdmin onImpersonate={(ownerId) => {
        setImpersonatingOwner(ownerId);
        setCurrentRole(UserRole.OWNER);
        setActiveTab('dashboard');
      }} />;
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard role={currentRole} />;
      case 'properties': return <Properties />;
      case 'residents': return <Residents />;
      case 'payments': return <Payments />;
      case 'complaints': return <Complaints role={currentRole} />;
      case 'superadmin': return <SuperAdmin onImpersonate={setImpersonatingOwner} />;
      default: return <Dashboard role={currentRole} />;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      {/* Impersonation Banner */}
      {impersonatingOwner && (
        <div className="fixed top-0 left-0 right-0 bg-red-600 text-white text-center py-2 z-[60] font-medium flex justify-between px-6 items-center">
          <span>You are viewing <strong>Owner: {impersonatingOwner}</strong> account as Superadmin.</span>
          <button 
            onClick={() => {
              setImpersonatingOwner(null);
              setCurrentRole(UserRole.SUPERADMIN);
              setActiveTab('superadmin');
            }}
            className="bg-white text-red-600 px-3 py-1 rounded text-sm hover:bg-red-50 transition"
          >
            Exit Impersonation
          </button>
        </div>
      )}

      <Sidebar 
        isOpen={isSidebarOpen} 
        setOpen={setSidebarOpen} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab}
        role={currentRole}
      />

      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'lg:ml-64' : 'ml-0'} ${impersonatingOwner ? 'pt-10' : ''}`}>
        <Header 
          toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} 
          role={currentRole}
          setRole={setCurrentRole}
        />
        <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { UserRole } from '../types';
import { Icons, COLORS } from '../constants';

interface SidebarProps {
  isOpen: boolean;
  setOpen: (open: boolean) => void;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  role: UserRole;
}

const Sidebar: React.FC<SidebarProps> = ({ isOpen, setOpen, activeTab, setActiveTab, role }) => {
  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: Icons.Dashboard },
    { id: 'properties', label: 'Properties', icon: Icons.Property, roles: [UserRole.OWNER, UserRole.MANAGER] },
    { id: 'residents', label: 'Residents', icon: Icons.Users, roles: [UserRole.OWNER, UserRole.MANAGER, UserRole.STAFF] },
    { id: 'payments', label: 'Payments', icon: Icons.Payments, roles: [UserRole.OWNER, UserRole.MANAGER, UserRole.TENANT] },
    { id: 'complaints', label: 'Complaints', icon: Icons.Complaints },
    { id: 'superadmin', label: 'Admin Tools', icon: Icons.SuperAdmin, roles: [UserRole.SUPERADMIN] },
  ];

  return (
    <>
      {/* Mobile overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden"
          onClick={() => setOpen(false)}
        />
      )}

      <aside className={`fixed top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-50 transform transition-transform duration-300 lg:translate-x-0 ${isOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full">
          <div className="p-6 border-b border-slate-100 flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-blue-600 flex items-center justify-center text-white font-bold text-xl">H</div>
            <div>
              <h1 className="text-lg font-bold text-slate-900 leading-none">HostelPro</h1>
              <p className="text-xs text-slate-500 mt-1">Management Platform</p>
            </div>
          </div>

          <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
            {menuItems.filter(item => !item.roles || item.roles.includes(role)).map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id);
                  if (window.innerWidth < 1024) setOpen(false);
                }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-blue-50 text-blue-600 shadow-sm' 
                    : 'text-slate-600 hover:bg-slate-50'
                }`}
              >
                <item.icon />
                <span className="font-medium">{item.label}</span>
              </button>
            ))}
          </nav>

          <div className="p-4 border-t border-slate-100">
            <div className="bg-slate-50 rounded-xl p-4 flex items-center gap-3">
              <img src="https://picsum.photos/40/40" className="w-10 h-10 rounded-full bg-slate-200" alt="Profile" />
              <div className="overflow-hidden">
                <p className="text-sm font-semibold text-slate-900 truncate">Suresh Prabhu</p>
                <p className="text-xs text-slate-500 truncate lowercase">{role}</p>
              </div>
            </div>
          </div>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;

import React from 'react';
import { UserRole } from '../types';

interface HeaderProps {
  toggleSidebar: () => void;
  role: UserRole;
  setRole: (role: UserRole) => void;
}

const Header: React.FC<HeaderProps> = ({ toggleSidebar, role, setRole }) => {
  return (
    <header className="h-16 bg-white border-b border-slate-200 px-4 md:px-8 flex items-center justify-between sticky top-0 z-30">
      <div className="flex items-center gap-4">
        <button 
          onClick={toggleSidebar}
          className="p-2 rounded-lg hover:bg-slate-100 lg:hidden text-slate-600"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" /></svg>
        </button>
        <h2 className="text-xl font-semibold text-slate-800 hidden md:block">Hostel Management Pro</h2>
      </div>

      <div className="flex items-center gap-4">
        <div className="hidden sm:flex items-center bg-slate-100 rounded-lg p-1">
          {Object.values(UserRole).slice(0, 4).map((r) => (
            <button
              key={r}
              onClick={() => setRole(r)}
              className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${
                role === r ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              {r}
            </button>
          ))}
          <button
              onClick={() => setRole(UserRole.SUPERADMIN)}
              className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${
                role === UserRole.SUPERADMIN ? 'bg-white text-purple-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              ADMIN
          </button>
        </div>

        <div className="flex items-center gap-3">
          <button className="p-2 rounded-full hover:bg-slate-100 relative text-slate-600">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
            <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
          </button>
          <img src="https://picsum.photos/32/32" className="w-8 h-8 rounded-full ring-2 ring-slate-100" alt="Avatar" />
        </div>
      </div>
    </header>
  );
};

