    const handleResize = () => {
      if (window.innerWidth < 1024) setSidebarOpen(false);
      else setSidebarOpen(true);
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleLoginSuccess = (role: UserRole) => {
    setCurrentRole(role);
    setIsAuthenticated(true);
    setActiveTab('dashboard');
  };

  const handleSignupSuccess = (role: UserRole) => {
    setCurrentRole(role);
    setIsAuthenticated(true);
    setActiveTab('dashboard');
    if (role === UserRole.OWNER) {
      setShowPlanSelection(true);
    }
  };

  if (!isAuthenticated) {
    if (isSigningUp) {
      return <Signup onSignupSuccess={handleSignupSuccess} onNavigateToLogin={() => setIsSigningUp(false)} />;
    }
    return <Login onLogin={handleLoginSuccess} onNavigateToSignup={() => setIsSigningUp(true)} />;
  }

  const renderContent = () => {
    if (currentRole === UserRole.SUPERADMIN && !impersonatingOwner) {
      return <SuperAdmin onImpersonate={(ownerId) => {
        setImpersonatingOwner(ownerId);
        setCurrentRole(UserRole.OWNER);
        setActiveTab('dashboard');
      }} />;
    }

    if (currentRole === UserRole.RESIDENT) {
      if (activeTab === 'dashboard') return <ResidentApp />;
      if (activeTab === 'payments') return <Payments />;
      if (activeTab === 'complaints') return <Complaints role={currentRole} />;
      return <ResidentApp />;
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard role={currentRole} />;
      case 'properties': return <Properties />;
      case 'residents': return <Residents />;
      case 'payments': return <Payments />;
      case 'complaints': return <Complaints role={currentRole} />;
      case 'expenses': return (
        <div className="p-12 text-center text-slate-400">
           <div className="w-16 h-16 bg-slate-100 rounded-full mx-auto mb-4 flex items-center justify-center">₹</div>
           <h3 className="font-bold text-slate-900">Expenses Tracker</h3>
           <p className="max-w-xs mx-auto mt-2">Daily expense recording for on-ground staff and owners. (Coming Soon)</p>
        </div>
      );
      case 'superadmin': return <SuperAdmin onImpersonate={setImpersonatingOwner} />;
      default: return <Dashboard role={currentRole} />;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      {/* Plan Selection Popup */}
      {showPlanSelection && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-md"></div>
          <div className="relative bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl overflow-hidden p-8 md:p-12 animate-in zoom-in duration-300">
            <div className="text-center mb-10">
              <h2 className="text-3xl font-black text-slate-900 mb-2">Welcome to Hostel Pro!</h2>
              <p className="text-slate-500">Choose the perfect plan to grow your property business.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {[
                { name: 'Standard', price: '₹999', features: ['3 Properties', '10 Staff', '300 Residents'] },
                { name: 'Pro', price: '₹2,499', features: ['10 Properties', '50 Staff', '1,000 Residents'], popular: true },
                { name: 'Enterprise', price: 'Custom', features: ['Unlimited Properties', 'Unlimited Staff', 'Full Branding'] }
              ].map(plan => (
                <div key={plan.name} className={`relative p-6 rounded-3xl border-2 transition-all hover:scale-105 ${plan.popular ? 'border-blue-600 shadow-xl shadow-blue-50' : 'border-slate-100'}`}>
                  {plan.popular && <span className="absolute -top-3 left-1/2 -translate-x-1/2 bg-blue-600 text-white px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest">Most Popular</span>}
                  <h3 className="text-xl font-black text-slate-900 mb-1">{plan.name}</h3>
                  <div className="flex items-baseline gap-1 mb-6">
                    <span className="text-3xl font-black text-slate-900">{plan.price}</span>
                    <span className="text-slate-400 text-sm">/month</span>
                  </div>
                  <ul className="space-y-4 mb-8">
                    {plan.features.map(f => (
                      <li key={f} className="flex items-center gap-3 text-sm text-slate-600">
                        <svg className="w-5 h-5 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"/></svg>
                        {f}
                      </li>
                    ))}
                  </ul>
                  <button 
                    onClick={() => setShowPlanSelection(false)}
                    className={`w-full py-3 rounded-2xl font-bold transition ${plan.popular ? 'bg-blue-600 text-white hover:bg-blue-700' : 'bg-slate-900 text-white hover:bg-slate-800'}`}
                  >
                    Select Plan
                  </button>
                </div>
              ))}
            </div>
            <button 
              onClick={() => setShowPlanSelection(false)}
              className="mt-8 w-full text-slate-400 text-sm font-bold uppercase tracking-widest hover:text-slate-600 transition"
            >
              Start 14-day Free Trial instead
            </button>
          </div>
        </div>
      )}

      {impersonatingOwner && (
        <div className="fixed top-0 left-0 right-0 bg-rose-600 text-white text-center py-2 z-[60] font-bold text-xs uppercase tracking-widest flex justify-between px-6 items-center shadow-lg">
          <span>SUPERADMIN ACCESS: VIEWING OWNER <strong>{impersonatingOwner}</strong></span>
          <button 
            onClick={() => {
              setImpersonatingOwner(null);
              setCurrentRole(UserRole.SUPERADMIN);
              setActiveTab('superadmin');
            }}
            className="bg-white text-rose-600 px-3 py-1 rounded-full text-[10px] hover:bg-rose-50 transition"
          >
            Exit Impersonation
          </button>
        </div>
      )}

      <Sidebar 
        isOpen={isSidebarOpen} 
        setOpen={setSidebarOpen} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab}
        role={currentRole}
      />

      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'lg:ml-64' : 'ml-0'} ${impersonatingOwner ? 'pt-10' : ''}`}>
        <Header 
          toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} 
          role={currentRole}
          setRole={setCurrentRole}
          onLogout={() => setIsAuthenticated(false)}
        />
        <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-10">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

