import React, { useState, useEffect } from 'react';
import { UserRole } from '../types';
import { mockResidents, mockStaff } from '../services/mockData';

interface SignupProps {
  onSignupSuccess: (role: UserRole) => void;
  onNavigateToLogin: () => void;
}

type SignupStep = 'form' | 'verify' | 'success';

const Signup: React.FC<SignupProps> = ({ onSignupSuccess, onNavigateToLogin }) => {
  const [role, setRole] = useState<UserRole>(UserRole.OWNER);
  const [step, setStep] = useState<SignupStep>('form');

  // Form Fields
  const [ownerEmail, setOwnerEmail] = useState('');
  const [yourEmail, setYourEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState('');
  const [error, setError] = useState('');

  const handleSignUpClick = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (password !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }

    // Validation for Staff/Resident
    if (role !== UserRole.OWNER) {
      const emailExists = role === UserRole.RESIDENT 
        ? mockResidents.some(r => r.email.toLowerCase() === yourEmail.toLowerCase())
        : mockStaff.some(s => s.email.toLowerCase() === yourEmail.toLowerCase());

      if (!emailExists) {
        setError(`This email is not registered by an owner. Please ask your property owner to add you as a ${role === UserRole.RESIDENT ? 'Resident' : 'Staff'} first.`);
        return;
      }
    }

    setStep('verify');
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp === '123456' || otp.length === 6) { // Accept 123456 as default mock OTP
      setStep('success');
      setTimeout(() => {
        onSignupSuccess(role);
      }, 1500);
    } else {
      setError('Invalid OTP. Try 123456');
    }
  };

  if (step === 'verify') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md bg-white rounded-3xl shadow-xl p-8 border border-slate-100 animate-in fade-in zoom-in duration-300">
          <div className="text-center mb-8">
            <div className="w-16 h-16 bg-blue-600 rounded-full mx-auto flex items-center justify-center text-white mb-6">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
            </div>
            <h2 className="text-2xl font-bold text-slate-900 mb-2">Verify Email</h2>
            <p className="text-slate-500 text-sm">We've sent a 6-digit code to <br/><span className="font-semibold text-slate-700">{role === UserRole.OWNER ? `${username}@hostelpro.com` : yourEmail}</span></p>
          </div>

          <form onSubmit={handleVerifyOtp} className="space-y-6">
            <div>
              <input 
                type="text" 
                maxLength={6}
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                className="w-full text-center tracking-[1em] text-2xl font-bold py-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
                placeholder="000000"
              />
            </div>
            {error && <p className="text-xs font-bold text-red-500 text-center">{error}</p>}
            <button type="submit" className="w-full py-4 bg-blue-600 text-white font-bold rounded-2xl shadow-lg hover:bg-blue-700 transition">
              Verify & Complete Signup
            </button>
            <p className="text-center text-xs text-slate-400 font-bold uppercase tracking-widest">Resend code in 0:59</p>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'success') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md bg-white rounded-3xl shadow-xl p-12 text-center animate-in zoom-in duration-500">
          <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full mx-auto flex items-center justify-center mb-6">
            <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold text-slate-900 mb-2">Welcome Aboard!</h2>
          <p className="text-slate-500">Your account has been created successfully. Redirecting you to the platform...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-3xl shadow-xl p-8 border border-slate-100">
        <div className="text-center mb-6">
          <div className="w-16 h-16 bg-blue-600 rounded-full mx-auto flex items-center justify-center text-white mb-4">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
            </svg>
          </div>
          <h1 className="text-2xl font-bold text-slate-900">Create Account</h1>
          <p className="text-slate-500 text-xs mt-1">Sign up as property owner, staff, or resident</p>
        </div>

        {/* Role Tabs */}
        <div className="flex bg-slate-100 p-1 rounded-xl mb-6">
          {[UserRole.OWNER, UserRole.STAFF, UserRole.RESIDENT].map(r => (
            <button
              key={r}
              type="button"
              onClick={() => { setRole(r); setError(''); }}
              className={`flex-1 py-2 text-xs font-semibold rounded-lg transition ${role === r ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {r.charAt(0) + r.slice(1).toLowerCase()}
            </button>
          ))}
        </div>

        <form onSubmit={handleSignUpClick} className="space-y-4">
          {/* Owner-Specific Preview */}
          {role === UserRole.OWNER && (
             <div className="space-y-4">
                <div>
                  <label className="text-xs font-bold text-slate-700 mb-1.5 block">Username</label>
                  <input 
                    type="text" 
                    value={username}
                    onChange={(e) => setUsername(e.target.value.replace(/[^a-zA-Z0-9_]/g, ''))}
                    className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition" 
                    placeholder="ae"
                    required
                  />
                  <p className="text-[10px] text-slate-500 mt-1">Only letters, numbers, and underscores allowed</p>
                  {username && <p className="text-[10px] text-blue-600 font-bold mt-1">Your email will be: {username}@hostelpro.com</p>}
                </div>
             </div>
          )}

          {/* Staff/Resident Specific Fields */}
          {role !== UserRole.OWNER && (
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-slate-700 mb-1.5 block">Owner's Email</label>
                <input 
                  type="email" 
                  value={ownerEmail}
                  onChange={(e) => setOwnerEmail(e.target.value)}
                  className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition" 
                  placeholder="owner@example.com"
                  required
                />
                <p className="text-[10px] text-slate-500 mt-1">Enter the email of the property owner who added you</p>
