import { Property, Resident, Complaint, Staff } from '../types';

// Helper to get data from local storage or return empty arrays
const getStorage = <T>(key: string): T[] => {
  const data = localStorage.getItem(`hostelpro_${key}`);
  return data ? JSON.parse(data) : [];
};

const setStorage = <T>(key: string, data: T[]) => {
  localStorage.setItem(`hostelpro_${key}`, JSON.stringify(data));
};

// Simulated Database
export const db = {
  getUsers: () => getStorage<any>('users'),
  saveUser: (user: any) => {
    const users = getStorage<any>('users');
    setStorage('users', [...users, user]);
  },

  getProperties: (ownerId?: string) => {
    const props = getStorage<Property>('properties');
    return ownerId ? props.filter(p => p.tenantId === ownerId) : props;
  },
  saveProperty: (prop: Property) => {
    const props = getStorage<Property>('properties');
    setStorage('properties', [...props, prop]);
  },

  getResidents: (ownerId?: string) => {
    const res = getStorage<Resident>('residents');
    return ownerId ? res.filter(r => r.ownerId === ownerId) : res;
  },
  saveResident: (res: Resident) => {
    const residents = getStorage<Resident>('residents');
    setStorage('residents', [...residents, res]);
  },
  deleteResident: (id: string) => {
    const residents = getStorage<Resident>('residents');
    setStorage('residents', residents.filter(r => r.id !== id));
  },

  getStaff: (ownerId?: string) => {
    const staff = getStorage<Staff>('staff');
    return ownerId ? staff.filter(s => s.ownerId === ownerId) : staff;
  },
  saveStaff: (s: Staff) => {
    const staff = getStorage<Staff>('staff');
    setStorage('staff', [...staff, s]);
  },

  getComplaints: (ownerId?: string) => {
    const complaints = getStorage<Complaint>('complaints');
    // For simplicity, complaints are filtered by owner context
    return complaints;
  },
  saveComplaint: (c: Complaint) => {
    const complaints = getStorage<Complaint>('complaints');
    setStorage('complaints', [...complaints, c]);
  }
};

