              className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500" 
              placeholder="username"
              required
            />
          </div>

          <div>
            <label className="text-xs font-bold text-slate-700 mb-1.5 block">Password</label>
            <input 
              type="password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500" 
              placeholder="••••••••"
              required
            />
          </div>

          <div>
            <label className="text-xs font-bold text-slate-700 mb-1.5 block">Confirm Password</label>
            <input 
              type="password" 
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              className="w-full px-4 py-2.5 bg-white border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500" 
              placeholder="••••••••"
              required
            />
          </div>

          {error && <p className="text-xs font-bold text-red-500 bg-red-50 p-3 rounded-lg">{error}</p>}

          <button type="submit" className="w-full py-3.5 bg-blue-600 text-white font-bold rounded-xl shadow-md hover:bg-blue-700 transition">
            Sign Up
          </button>
        </form>

        <div className="mt-6 text-center">
          <p className="text-sm text-slate-500">
            Already have an account? {' '}
            <button onClick={onNavigateToLogin} className="text-blue-600 font-bold hover:underline">Sign in</button>
          </p>
        </div>
      </div>
    </div>
  );
};

