    { id: 'complaints', label: 'Complaints', icon: Icons.Complaints, roles: [UserRole.OWNER, UserRole.STAFF, UserRole.RESIDENT] },
    { id: 'expenses', label: 'Expenses', icon: Icons.Expenses, roles: [UserRole.OWNER, UserRole.STAFF] },
    { id: 'superadmin', label: 'Superadmin', icon: Icons.SuperAdmin, roles: [UserRole.SUPERADMIN] },
  ];

  return (
    <>
      {isOpen && (
        <div className="fixed inset-0 bg-black/50 z-40 lg:hidden" onClick={() => setOpen(false)} />
      )}

      <aside className={`fixed top-0 left-0 h-full w-64 bg-white border-r border-slate-200 z-50 transform transition-transform duration-300 lg:translate-x-0 ${isOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full">
          <div className="p-6 border-b border-slate-100 flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-blue-600 flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-blue-100">H</div>
            <div>
              <h1 className="text-lg font-bold text-slate-900 leading-none">Hostel Pro</h1>
              <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase tracking-widest">SaaS Edition</p>
            </div>
          </div>

          <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
            {menuItems.filter(item => (item.roles as readonly UserRole[]).includes(role)).map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setActiveTab(item.id);
                  if (window.innerWidth < 1024) setOpen(false);
                }}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${
                  activeTab === item.id 
                    ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' 
                    : 'text-slate-600 hover:bg-slate-50'
                }`}
              >
                <item.icon />
                <span className="font-semibold text-sm">{item.label}</span>
              </button>
            ))}
          </nav>

          {role === UserRole.OWNER && (
            <div className="p-4 border-t border-slate-100">
               <div className="bg-slate-900 rounded-2xl p-4 relative overflow-hidden group">
                  <div className="relative z-10">
                     <p className="text-white text-[10px] font-black uppercase mb-1 tracking-widest opacity-60">My Active Plan</p>
                     <p className={`font-black uppercase tracking-tight mb-3 ${
                       planTier === SubscriptionTier.ENTERPRISE ? 'text-purple-400' :
                       planTier === SubscriptionTier.PRO ? 'text-blue-400' :
                       planTier === SubscriptionTier.STANDARD ? 'text-emerald-400' :
                       'text-slate-300'
                     }`}>
                       {planTier || 'NO PLAN'} Tier
                     </p>
                     <button className="w-full py-2 bg-white/10 text-white text-[10px] font-bold rounded-lg hover:bg-white/20 transition">Settings</button>
                  </div>
                  <div className="absolute top-0 right-0 -mr-4 -mt-4 w-16 h-16 bg-blue-600/20 rounded-full blur-2xl group-hover:bg-blue-600/30 transition"></div>
               </div>
            </div>
          )}
        </div>
      </aside>
    </>
  );
};

