import React, { useState } from 'react';
import { db } from '../services/mockData';
import { formatCurrency } from '../constants';
import { Property, PLAN_LIMITS } from '../types';
import UpgradeModal from './UpgradeModal';

interface PropertiesProps {
  ownerId: string;
  onUpgrade: () => void;
}

const Properties: React.FC<PropertiesProps> = ({ ownerId, onUpgrade }) => {
  const [properties, setProperties] = useState<Property[]>(db.getProperties(ownerId));
  const [showAddModal, setShowAddModal] = useState(false);
  const [showUpgradeModal, setShowUpgradeModal] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [city, setCity] = useState('');
  const [address, setAddress] = useState('');
  const [rooms, setRooms] = useState('');

  const user = db.getUsers().find((u: any) => u.id === ownerId);
  const plan = user?.plan ? PLAN_LIMITS[user.plan] : PLAN_LIMITS.FREE;

  const handleTryAdd = () => {
    if (plan.properties !== null && properties.length >= plan.properties) {
      setShowUpgradeModal(true);
      return;
    }
    setShowAddModal(true);
  };

  const handleAddProperty = (e: React.FormEvent) => {
    e.preventDefault();
    const newProp: Property = {
      id: `PROP-${Date.now()}`,
      tenantId: ownerId,
      name,
      city,
      address,
      totalRooms: parseInt(rooms),
      occupiedRooms: 0,
      revenue: 0,
      assignedStaffIds: []
    };
    db.saveProperty(newProp);
    setProperties(db.getProperties(ownerId));
    setShowAddModal(false);
    setName(''); setCity(''); setAddress(''); setRooms('');
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">My Hostels</h1>
          <p className="text-slate-500">Manage all your physical properties here.</p>
        </div>
        <button 
          onClick={handleTryAdd}
          className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-blue-700 transition"
        >
          + Add New Property
        </button>
      </div>

      <UpgradeModal 
        isOpen={showUpgradeModal}
        onClose={() => setShowUpgradeModal(false)}
        onUpgrade={() => {
          setShowUpgradeModal(false);
          onUpgrade();
        }}
        limitType="properties"
        limitValue={plan.properties || 0}
      />

      {properties.length === 0 ? (
        <div className="bg-white border-2 border-dashed border-slate-200 rounded-[2.5rem] p-16 text-center">
           <div className="w-16 h-16 bg-slate-50 rounded-2xl mx-auto flex items-center justify-center text-slate-400 mb-6">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
           </div>
           <h3 className="text-xl font-bold text-slate-900 mb-2">Setup Your First Property</h3>
           <p className="text-slate-500 max-w-xs mx-auto mb-8">Click the button above to start managing your hostel rooms and residents.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
          {properties.map((p) => (
            <div key={p.id} className="bg-white rounded-2xl border border-slate-200 overflow-hidden hover:shadow-lg transition group">
              <div className="h-40 bg-slate-100 flex items-center justify-center">
                 <svg className="w-12 h-12 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
              </div>
              <div className="p-6">
                <div className="flex justify-between items-start mb-2">
                  <div>
                    <h3 className="text-lg font-bold text-slate-900">{p.name}</h3>
                    <p className="text-sm text-slate-500">{p.city}, {p.address}</p>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4 mt-6">
                    <div className="bg-slate-50 p-3 rounded-xl text-center">
                      <p className="text-[10px] text-slate-400 font-black uppercase">Total Rooms</p>
                      <p className="text-lg font-black text-slate-900">{p.totalRooms}</p>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl text-center">
                      <p className="text-[10px] text-slate-400 font-black uppercase">Revenue</p>
                      <p className="text-lg font-black text-emerald-600">{formatCurrency(p.revenue)}</p>
                    </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowAddModal(false)}></div>
          <div className="relative bg-white w-full max-w-lg rounded-2xl shadow-2xl">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <h2 className="text-xl font-black text-slate-900">Add Property</h2>
              <button onClick={() => setShowAddModal(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <form onSubmit={handleAddProperty} className="p-8 space-y-4">
