              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-black text-slate-400 uppercase">City</label>
                  <input required value={city} onChange={(e) => setCity(e.target.value)} type="text" placeholder="Bangalore" className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-black text-slate-400 uppercase">Total Rooms</label>
                  <input required value={rooms} onChange={(e) => setRooms(e.target.value)} type="number" placeholder="20" className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none" />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-xs font-black text-slate-400 uppercase">Address</label>
                <textarea required value={address} onChange={(e) => setAddress(e.target.value)} placeholder="Full street details" className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg outline-none"></textarea>
              </div>
              <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black uppercase tracking-widest rounded-xl shadow-lg hover:bg-blue-700 transition">Create Property</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Properties;

import React, { useState } from 'react';
import { db } from '../services/mockData';
import { formatCurrency } from '../constants';
import { Resident, PLAN_LIMITS } from '../types';
import UpgradeModal from './UpgradeModal';

interface ResidentsProps {
  ownerId: string;
  onUpgrade: () => void;
}

const Residents: React.FC<ResidentsProps> = ({ ownerId, onUpgrade }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [residents, setResidents] = useState<Resident[]>(db.getResidents(ownerId));
  const [showAdd, setShowAdd] = useState(false);
  const [showUpgradeModal, setShowUpgradeModal] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [rent, setRent] = useState('');

  const user = db.getUsers().find((u: any) => u.id === ownerId);
  const plan = user?.plan ? PLAN_LIMITS[user.plan] : PLAN_LIMITS.FREE;

  const handleTryAdd = () => {
    if (plan.residents !== null && residents.length >= plan.residents) {
      setShowUpgradeModal(true);
      return;
    }
    setShowAdd(true);
  };

  const filteredResidents = residents.filter(r => 
    r.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    r.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleAddResident = (e: React.FormEvent) => {
    e.preventDefault();
    const newRes: Resident = {
      id: `RES-${Date.now()}`,
      ownerId,
      name,
      email,
      phone,
      unitId: 'U-DEMO',
      propertyId: 'P-DEMO',
      moveInDate: new Date().toISOString().split('T')[0],
      dueDate: 5,
      status: 'active',
      rent: parseInt(rent)
    };
    db.saveResident(newRes);
    setResidents(db.getResidents(ownerId));
    setShowAdd(false);
    setName(''); setEmail(''); setPhone(''); setRent('');
  };

  const handleDeleteResident = (id: string) => {
    if (window.confirm('Delete this resident record? This cannot be undone.')) {
      db.deleteResident(id);
      setResidents(db.getResidents(ownerId));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900">Residents</h1>
          <p className="text-slate-500 font-medium">Add placeholders so your residents can sign up.</p>
        </div>
        <button 
          onClick={handleTryAdd}
          className="bg-blue-600 text-white px-5 py-3 rounded-2xl font-bold hover:bg-blue-700 transition"
        >
          + Add Resident
        </button>
      </div>

      <UpgradeModal 
        isOpen={showUpgradeModal}
        onClose={() => setShowUpgradeModal(false)}
        onUpgrade={() => {
          setShowUpgradeModal(false);
          onUpgrade();
        }}
        limitType="residents"
        limitValue={plan.residents || 0}
      />

      <div className="bg-white rounded-3xl shadow-sm border border-slate-100 p-6">
        <div className="relative mb-8">
          <svg className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <input 
            type="text" 
            placeholder="Search email or name..." 
            className="w-full pl-12 pr-6 py-4 bg-slate-50 border border-slate-50 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:bg-white focus:border-blue-500 transition"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto">
          {residents.length === 0 ? (
            <div className="py-20 text-center text-slate-400">
               <p>No residents found. Add a resident record to allow them to sign up.</p>
            </div>
          ) : (
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-4 py-5">Profile</th>
                  <th className="px-4 py-5">Rent Info</th>
                  <th className="px-4 py-5">Status</th>
                  <th className="px-4 py-5 text-right">Manage</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredResidents.map((r) => (
                  <tr key={r.id} className="hover:bg-slate-50/50 transition group">
                    <td className="px-4 py-6">
                      <div className="flex items-center gap-4">
                        <div className="w-11 h-11 rounded-full bg-slate-100 flex items-center justify-center font-bold text-slate-400">{r.name[0]}</div>
                        <div>
                          <p className="font-bold text-slate-900">{r.name}</p>
                          <p className="text-xs font-medium text-slate-500 lowercase">{r.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-4 py-6">
                      <p className="text-sm font-black text-slate-900">{formatCurrency(r.rent)}</p>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Due on {r.dueDate}th</p>
                    </td>
                    <td className="px-4 py-6">
                      <span className="px-2.5 py-1 bg-emerald-50 text-emerald-600 rounded-lg text-[10px] font-black uppercase tracking-widest">
                        ACTIVE
                      </span>
                    </td>
                    <td className="px-4 py-6 text-right">
                       <button 
                        onClick={() => handleDeleteResident(r.id)}
                        className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition"
                       >
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                       </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {showAdd && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowAdd(false)}></div>
          <div className="relative bg-white w-full max-w-xl rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
             <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
               <h2 className="text-xl font-black text-slate-900 uppercase tracking-widest">Add Resident Invitation</h2>
               <button onClick={() => setShowAdd(false)} className="text-slate-400 hover:text-slate-600">✕</button>
             </div>
             <form onSubmit={handleAddResident} className="p-8 space-y-6">
               <div className="bg-blue-50 p-4 rounded-xl text-blue-800 text-xs font-medium">
                 The resident must sign up using the exact email you enter below.
               </div>
               <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Full Name</label>
                   <input required value={name} onChange={(e) => setName(e.target.value)} type="text" placeholder="Rahul Sharma" className="w-full px-5 py-3 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-blue-500" />
                 </div>
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Email (Critical)</label>
                   <input required value={email} onChange={(e) => setEmail(e.target.value)} type="email" placeholder="rahul@gmail.com" className="w-full px-5 py-3 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-blue-500" />
                 </div>
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Phone</label>
                   <input required value={phone} onChange={(e) => setPhone(e.target.value)} type="tel" placeholder="9876543210" className="w-full px-5 py-3 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-blue-500" />
                 </div>
                 <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Monthly Rent</label>
                   <input required value={rent} onChange={(e) => setRent(e.target.value)} type="number" placeholder="8500" className="w-full px-5 py-3 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:border-blue-500" />
                 </div>
               </div>
               <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black uppercase tracking-widest rounded-2xl shadow-lg hover:bg-blue-700 transition">Create Record</button>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

