import React, { useState, useEffect } from 'react';
import { UserRole, SubscriptionTier } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Properties from './components/Properties';
import Residents from './components/Residents';
import Payments from './components/Payments';
import Complaints from './components/Complaints';
import SuperAdmin from './components/SuperAdmin';
import ResidentApp from './components/ResidentApp';
import Login from './components/Login';
import Signup from './components/Signup';
import PlanSelection from './components/PlanSelection';
import { db } from './services/mockData';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isSigningUp, setIsSigningUp] = useState(false);
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.OWNER);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [impersonatingOwner, setImpersonatingOwner] = useState<string | null>(null);
  const [showPlanSelection, setShowPlanSelection] = useState(false);
  const [forceOpenPropertyModal, setForceOpenPropertyModal] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 1024) setSidebarOpen(false);
      else setSidebarOpen(true);
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const getCurrentUser = () => {
    if (!currentUserId) return null;
    return db.getUsers().find((u: any) => u.id === currentUserId);
  };

  const user = getCurrentUser();

  const handleLoginSuccess = (role: UserRole, userId: string) => {
    setCurrentRole(role);
    setCurrentUserId(userId);
    setIsAuthenticated(true);
    setActiveTab('dashboard');

    // Check if owner needs to pick a plan
    if (role === UserRole.OWNER) {
      const u = db.getUsers().find((usr: any) => usr.id === userId);
      if (!u?.plan) {
        setShowPlanSelection(true);
      }
    }
  };

  const handleSignupSuccess = (role: UserRole, userId: string) => {
    setCurrentRole(role);
    setCurrentUserId(userId);
    setIsAuthenticated(true);
    setActiveTab('dashboard');
    if (role === UserRole.OWNER) {
      setShowPlanSelection(true);
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUserId(null);
    setImpersonatingOwner(null);
    setShowPlanSelection(false);
  };

  const handlePlanSelect = (tier: SubscriptionTier) => {
    if (currentUserId) {
      db.updateUserPlan(currentUserId, tier);
      setShowPlanSelection(false);
    }
  };

  const handleAddPropertyFromDash = () => {
    setActiveTab('properties');
    setForceOpenPropertyModal(true);
  };

  if (!isAuthenticated) {
    if (isSigningUp) {
      return <Signup onSignupSuccess={handleSignupSuccess} onNavigateToLogin={() => setIsSigningUp(false)} />;
    }
    return <Login onLogin={handleLoginSuccess} onNavigateToSignup={() => setIsSigningUp(true)} />;
  }

  if (showPlanSelection) {
    return <PlanSelection onSelect={handlePlanSelect} currentTier={user?.plan} />;
  }

  const effectiveOwnerId = impersonatingOwner || (currentRole === UserRole.OWNER ? currentUserId : null);

  const renderContent = () => {
    if (currentRole === UserRole.SUPERADMIN && !impersonatingOwner) {
      return <SuperAdmin onImpersonate={(ownerId) => {
        setImpersonatingOwner(ownerId);
        setCurrentRole(UserRole.OWNER);
        setActiveTab('dashboard');
      }} />;
    }

    if (currentRole === UserRole.RESIDENT) {
      const resId = currentUserId || '';
      if (activeTab === 'dashboard') return <ResidentApp residentId={resId} />;
      if (activeTab === 'payments') return <Payments ownerId={effectiveOwnerId || ''} />;
      if (activeTab === 'complaints') return <Complaints role={currentRole} ownerId={effectiveOwnerId || ''} />;
      return <ResidentApp residentId={resId} />;
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard role={currentRole} ownerId={effectiveOwnerId || ''} onAddProperty={handleAddPropertyFromDash} />;
      case 'properties': return (
        <Properties 
          ownerId={effectiveOwnerId || ''} 
          onUpgrade={() => setShowPlanSelection(true)} 
          forceOpenModal={forceOpenPropertyModal}
          onModalClose={() => setForceOpenPropertyModal(false)}
        />
      );
      case 'residents': return <Residents ownerId={effectiveOwnerId || ''} onUpgrade={() => setShowPlanSelection(true)} />;
      case 'payments': return <Payments ownerId={effectiveOwnerId || ''} />;
      case 'complaints': return <Complaints role={currentRole} ownerId={effectiveOwnerId || ''} />;
      case 'expenses': return (
        <div className="p-12 text-center text-slate-400">
           <div className="w-16 h-16 bg-slate-100 rounded-full mx-auto mb-4 flex items-center justify-center text-xl">INR</div>
           <h3 className="font-bold text-slate-900">Expenses Tracker</h3>
           <p className="max-w-xs mx-auto mt-2">Daily expense recording. (Coming Soon)</p>
        </div>
      );
      case 'superadmin': return <SuperAdmin onImpersonate={setImpersonatingOwner} />;
      default: return <Dashboard role={currentRole} ownerId={effectiveOwnerId || ''} onAddProperty={handleAddPropertyFromDash} />;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      {impersonatingOwner && (
        <div className="fixed top-0 left-0 right-0 bg-rose-600 text-white text-center py-2 z-[60] font-bold text-[10px] uppercase tracking-widest flex justify-between px-6 items-center shadow-lg">
          <span>SUPERADMIN ACCESS: VIEWING OWNER <strong>{impersonatingOwner}</strong></span>
          <button 
            onClick={() => {
              setImpersonatingOwner(null);
              setCurrentRole(UserRole.SUPERADMIN);
              setActiveTab('superadmin');
            }}
            className="bg-white text-rose-600 px-3 py-1 rounded-full text-[10px] hover:bg-rose-50 transition"
          >
            Exit Impersonation
          </button>
        </div>
      )}

      <Sidebar 
        isOpen={isSidebarOpen} 
        setOpen={setSidebarOpen} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab}
        role={currentRole}
        planTier={user?.plan}
      />

      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'lg:ml-64' : 'ml-0'} ${impersonatingOwner ? 'pt-10' : ''}`}>
        <Header 
          toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} 
          role={currentRole}
          onLogout={handleLogout}
        />
        <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-10">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { db } from '../services/mockData';
import { formatCurrency } from '../constants';
import { Property, PLAN_LIMITS } from '../types';
import UpgradeModal from './UpgradeModal';

interface PropertiesProps {
  ownerId: string;
  onUpgrade: () => void;
  forceOpenModal?: boolean;
  onModalClose?: () => void;
}

const Properties: React.FC<PropertiesProps> = ({ ownerId, onUpgrade, forceOpenModal, onModalClose }) => {
  const [properties, setProperties] = useState<Property[]>(db.getProperties(ownerId));
  const [showAddModal, setShowAddModal] = useState(false);
  const [showUpgradeModal, setShowUpgradeModal] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [type, setType] = useState('Hostel');
  const [address, setAddress] = useState('');
  const [city, setCity] = useState('');
  const [state, setState] = useState('');
  const [zipCode, setZipCode] = useState('');
  const [rooms, setRooms] = useState('');
  const [contactPerson, setContactPerson] = useState('');
  const [contactPhone, setContactPhone] = useState('');

  useEffect(() => {
    if (forceOpenModal) {
      handleTryAdd();
    }
  }, [forceOpenModal]);

  const user = db.getUsers().find((u: any) => u.id === ownerId);
  const plan = user?.plan ? PLAN_LIMITS[user.plan] : PLAN_LIMITS.FREE;

  const handleTryAdd = () => {
    if (plan.properties !== null && properties.length >= plan.properties) {
      setShowUpgradeModal(true);
      return;
    }
    setShowAddModal(true);
  };

  const handleCloseAddModal = () => {
    setShowAddModal(false);
    if (onModalClose) onModalClose();
  };

  const handleAddProperty = (e: React.FormEvent) => {
    e.preventDefault();
    const newProp: Property = {
      id: `PROP-${Date.now()}`,
      tenantId: ownerId,
      name,
      type,
      address,
      city,
      state,
      zipCode,
      totalRooms: parseInt(rooms) || 0,
      occupiedRooms: 0,
      revenue: 0,
      contactPerson,
      contactPhone,
      assignedStaffIds: []
    };
    db.saveProperty(newProp);
    setProperties(db.getProperties(ownerId));
    handleCloseAddModal();
    // Reset form
    setName(''); setType('Hostel'); setAddress(''); setCity('');
    setState(''); setZipCode(''); setRooms(''); 
    setContactPerson(''); setContactPhone('');
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">My Hostels</h1>
          <p className="text-slate-500">Manage all your physical properties here.</p>
        </div>
        <button 
          onClick={handleTryAdd}
          className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-blue-700 transition"
        >
          + Add New Property
        </button>
      </div>

      <UpgradeModal 
        isOpen={showUpgradeModal}
        onClose={() => setShowUpgradeModal(false)}
        onUpgrade={() => {
          setShowUpgradeModal(false);
          onUpgrade();
        }}
        limitType="properties"
        limitValue={plan.properties || 0}
      />

      {properties.length === 0 ? (
        <div className="bg-white border-2 border-dashed border-slate-200 rounded-[2.5rem] p-16 text-center">
           <div className="w-16 h-16 bg-slate-50 rounded-2xl mx-auto flex items-center justify-center text-slate-400 mb-6">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
           </div>
           <h3 className="text-xl font-bold text-slate-900 mb-2">Setup Your First Property</h3>
           <p className="text-slate-500 max-w-xs mx-auto mb-8">Click the button above to start managing your hostel rooms and residents.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
          {properties.map((p) => (
            <div key={p.id} className="bg-white rounded-2xl border border-slate-200 overflow-hidden hover:shadow-lg transition group">
              <div className="h-40 bg-slate-100 flex items-center justify-center">
                 <svg className="w-12 h-12 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
              </div>
              <div className="p-6">
                <div className="flex justify-between items-start mb-2">
                  <div>
                    <h3 className="text-lg font-bold text-slate-900">{p.name}</h3>
                    <p className="text-sm text-slate-500">{p.city}, {p.address}</p>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4 mt-6">
                    <div className="bg-slate-50 p-3 rounded-xl text-center">
                      <p className="text-[10px] text-slate-400 font-black uppercase">Total Rooms</p>
                      <p className="text-lg font-black text-slate-900">{p.totalRooms}</p>
                    </div>
                    <div className="bg-slate-50 p-3 rounded-xl text-center">
                      <p className="text-[10px] text-slate-400 font-black uppercase">Revenue</p>
