                    </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-[2px]" onClick={handleCloseAddModal}></div>
          <div className="relative bg-white w-full max-w-lg rounded-xl shadow-2xl animate-in zoom-in duration-200 overflow-hidden">
            <div className="p-6 pb-2 relative">
              <button 
                onClick={handleCloseAddModal} 
                className="absolute top-6 right-6 text-slate-400 hover:text-slate-600 transition"
