                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-bold text-slate-900">Property Type</label>
                  <select 
                    value={type} 
                    onChange={(e) => setType(e.target.value)} 
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500 transition text-sm font-medium appearance-none bg-white"
