export type UserRole = typeof UserRole[keyof typeof UserRole];

export const SubscriptionTier = {
  FREE: 'FREE',
  STANDARD: 'STANDARD',
  PRO: 'PRO',
  ENTERPRISE: 'ENTERPRISE'
} as const;

export type SubscriptionTier = typeof SubscriptionTier[keyof typeof SubscriptionTier];

export interface PlanLimit {
  properties: number | null;
  staff: number | null;
  residents: number | null;
  price: number;
}

export const PLAN_LIMITS: Record<SubscriptionTier, PlanLimit> = {
  [SubscriptionTier.FREE]: { properties: 1, staff: 2, residents: 10, price: 0 },
  [SubscriptionTier.STANDARD]: { properties: 3, staff: 15, residents: 130, price: 999 },
  [SubscriptionTier.PRO]: { properties: 10, staff: 60, residents: 600, price: 2499 },
  [SubscriptionTier.ENTERPRISE]: { properties: null, staff: null, residents: null, price: 9999 }
};

export const RoomStatus = {
  VACANT: 'Vacant',
  PARTIALLY_OCCUPIED: 'Partially Occupied',
  FULL: 'Full'
} as const;

export type RoomStatus = typeof RoomStatus[keyof typeof RoomStatus];

export const ComplaintStatus = {
  OPEN: 'Open',
  IN_PROGRESS: 'In Progress',
  RESOLVED: 'Resolved'
} as const;

export type ComplaintStatus = typeof ComplaintStatus[keyof typeof ComplaintStatus];

