import React, { useState, useEffect } from 'react';
import { UserRole, SubscriptionTier } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Properties from './components/Properties';
import Residents from './components/Residents';
import Payments from './components/Payments';
import Complaints from './components/Complaints';
import Rooms from './components/Rooms';
import SuperAdmin from './components/SuperAdmin';
import ResidentApp from './components/ResidentApp';
import Login from './components/Login';
import Signup from './components/Signup';
import PlanSelection from './components/PlanSelection';
import { db } from './services/mockData';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isSigningUp, setIsSigningUp] = useState(false);
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.OWNER);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [impersonatingOwner, setImpersonatingOwner] = useState<string | null>(null);
  const [showPlanSelection, setShowPlanSelection] = useState(false);
  const [forceOpenPropertyModal, setForceOpenPropertyModal] = useState(false);
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 1024) setSidebarOpen(false);
      else setSidebarOpen(true);
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const getCurrentUser = () => {
    if (!currentUserId) return null;
    return db.getUsers().find((u: any) => u.id === currentUserId);
  };

  const user = getCurrentUser();

  const handleLoginSuccess = (role: UserRole, userId: string) => {
    setCurrentRole(role);
    setCurrentUserId(userId);
    setIsAuthenticated(true);
    setActiveTab('dashboard');

    // Check if owner needs to pick a plan
    if (role === UserRole.OWNER) {
      const u = db.getUsers().find((usr: any) => usr.id === userId);
      if (!u?.plan) {
        setShowPlanSelection(true);
      }
    }
  };

  const handleSignupSuccess = (role: UserRole, userId: string) => {
    setCurrentRole(role);
    setCurrentUserId(userId);
    setIsAuthenticated(true);
    setActiveTab('dashboard');
    if (role === UserRole.OWNER) {
      setShowPlanSelection(true);
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUserId(null);
    setImpersonatingOwner(null);
    setShowPlanSelection(false);
  };

  const handlePlanSelect = (tier: SubscriptionTier) => {
    if (currentUserId) {
      db.updateUserPlan(currentUserId, tier);
      setShowPlanSelection(false);
    }
  };

  const handleAddPropertyFromDash = () => {
    setActiveTab('properties');
    setForceOpenPropertyModal(true);
  };

  const handleManageRooms = (propertyId: string) => {
    setSelectedPropertyId(propertyId);
    setActiveTab('rooms');
  };

  if (!isAuthenticated) {
    if (isSigningUp) {
      return <Signup onSignupSuccess={handleSignupSuccess} onNavigateToLogin={() => setIsSigningUp(false)} />;
    }
    return <Login onLogin={handleLoginSuccess} onNavigateToSignup={() => setIsSigningUp(true)} />;
  }

  if (showPlanSelection) {
    return <PlanSelection onSelect={handlePlanSelect} currentTier={user?.plan} />;
  }

  const effectiveOwnerId = impersonatingOwner || (currentRole === UserRole.OWNER ? currentUserId : null);

  const renderContent = () => {
    if (currentRole === UserRole.SUPERADMIN && !impersonatingOwner) {
      return <SuperAdmin onImpersonate={(ownerId) => {
        setImpersonatingOwner(ownerId);
        setCurrentRole(UserRole.OWNER);
        setActiveTab('dashboard');
      }} />;
    }

    if (currentRole === UserRole.RESIDENT) {
      const resId = currentUserId || '';
      if (activeTab === 'dashboard') return <ResidentApp residentId={resId} />;
      if (activeTab === 'payments') return <Payments ownerId={effectiveOwnerId || ''} />;
      if (activeTab === 'complaints') return <Complaints role={currentRole} ownerId={effectiveOwnerId || ''} />;
      return <ResidentApp residentId={resId} />;
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard role={currentRole} ownerId={effectiveOwnerId || ''} onAddProperty={handleAddPropertyFromDash} />;
      case 'properties': return (
        <Properties 
          ownerId={effectiveOwnerId || ''} 
          onUpgrade={() => setShowPlanSelection(true)} 
          forceOpenModal={forceOpenPropertyModal}
          onModalClose={() => setForceOpenPropertyModal(false)}
          onManageRooms={handleManageRooms}
        />
      );
      case 'rooms': return (
        <Rooms 
          ownerId={effectiveOwnerId || ''} 
          initialPropertyId={selectedPropertyId} 
          onUpgrade={() => setShowPlanSelection(true)} 
        />
      );
      case 'residents': return <Residents ownerId={effectiveOwnerId || ''} onUpgrade={() => setShowPlanSelection(true)} />;
      case 'payments': return <Payments ownerId={effectiveOwnerId || ''} />;
      case 'complaints': return <Complaints role={currentRole} ownerId={effectiveOwnerId || ''} />;
      case 'expenses': return (
        <div className="p-12 text-center text-slate-400">
           <div className="w-16 h-16 bg-slate-100 rounded-full mx-auto mb-4 flex items-center justify-center text-xl">INR</div>
           <h3 className="font-bold text-slate-900">Expenses Tracker</h3>
           <p className="max-w-xs mx-auto mt-2">Daily expense recording. (Coming Soon)</p>
        </div>
      );
      case 'superadmin': return <SuperAdmin onImpersonate={setImpersonatingOwner} />;
      default: return <Dashboard role={currentRole} ownerId={effectiveOwnerId || ''} onAddProperty={handleAddPropertyFromDash} />;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      {impersonatingOwner && (
        <div className="fixed top-0 left-0 right-0 bg-rose-600 text-white text-center py-2 z-[60] font-bold text-[10px] uppercase tracking-widest flex justify-between px-6 items-center shadow-lg">
          <span>SUPERADMIN ACCESS: VIEWING OWNER <strong>{impersonatingOwner}</strong></span>
          <button 
            onClick={() => {
              setImpersonatingOwner(null);
              setCurrentRole(UserRole.SUPERADMIN);
              setActiveTab('superadmin');
            }}
            className="bg-white text-rose-600 px-3 py-1 rounded-full text-[10px] hover:bg-rose-50 transition"
          >
            Exit Impersonation
          </button>
        </div>
      )}

      <Sidebar 
        isOpen={isSidebarOpen} 
        setOpen={setSidebarOpen} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab}
        role={currentRole}
        planTier={user?.plan}
      />

      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'lg:ml-64' : 'ml-0'} ${impersonatingOwner ? 'pt-10' : ''}`}>
        <Header 
          toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} 
          role={currentRole}
          onLogout={handleLogout}
        />
        <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-10">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

