  const [address, setAddress] = useState('');
  const [city, setCity] = useState('');
  const [state, setState] = useState('');
  const [zipCode, setZipCode] = useState('');
  const [rooms, setRooms] = useState('');
  const [contactPerson, setContactPerson] = useState('');
  const [contactPhone, setContactPhone] = useState('');

  // Handle force open from Dashboard
  useEffect(() => {
    if (forceOpenModal) {
      const user = db.getUsers().find((u: any) => u.id === ownerId);
      const plan = user?.plan ? PLAN_LIMITS[user.plan] : PLAN_LIMITS.FREE;
      const currentProps = db.getProperties(ownerId);

      if (plan.properties !== null && currentProps.length >= plan.properties) {
        setShowUpgradeModal(true);
      } else {
        setShowAddModal(true);
      }

      // Notify App that we've processed the force open
      if (onModalClose) onModalClose();
    }
