    e.preventDefault();
    const newProp: Property = {
      id: `PROP-${Date.now()}`,
      tenantId: ownerId,
      name,
      type,
      address,
      city,
      state,
      zipCode,
      totalRooms: parseInt(rooms) || 0,
      occupiedRooms: 0,
      revenue: 0,
      contactPerson,
      contactPhone,
      assignedStaffIds: []
    };
    db.saveProperty(newProp);
    setProperties(db.getProperties(ownerId));
    handleCloseAddModal();
    // Reset form
    setName(''); setType('Boys'); setAddress(''); setCity('');
    setState(''); setZipCode(''); setRooms(''); 
