                  </div>
                </div>

                {/* Add/View Rooms Button */}
                <button 
                  onClick={() => onManageRooms(p.id)}
                  className="w-full mt-4 py-2 bg-slate-50 text-slate-900 font-bold rounded-xl border border-slate-200 hover:bg-slate-100 transition text-sm flex items-center justify-center gap-2"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 10h16M4 14h16M4 18h16" /></svg>
                  Add / View Rooms
