                    >
                      <option value="Girls/Women">Girls/Women</option>
                      <option value="Boys">Boys</option>
                      <option value="Co-live">Co-live</option>
                    </select>
                    <svg className="w-4 h-4 absolute right-2.5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-sm font-bold text-slate-900">Address</label>
                <input 
                  required 
                  value={address} 
                  onChange={(e) => setAddress(e.target.value)} 
                  type="text" 
                  placeholder="Full address" 
                  className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500 transition text-sm font-medium" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-bold text-slate-900">City</label>
                  <input 
                    required 
                    value={city} 
                    onChange={(e) => setCity(e.target.value)} 
                    type="text" 
                    placeholder="City" 
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500 transition text-sm font-medium" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-bold text-slate-900">State</label>
                  <input 
                    required 
                    value={state} 
                    onChange={(e) => setState(e.target.value)} 
                    type="text" 
                    placeholder="State" 
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500 transition text-sm font-medium" 
                  />
