              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-bold text-slate-900">ZIP Code</label>
                  <input 
                    required 
                    value={zipCode} 
                    onChange={(e) => setZipCode(e.target.value)} 
                    type="text" 
                    placeholder="ZIP code" 
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500 transition text-sm font-medium" 
                  />
