                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500 transition text-sm font-medium" 
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-sm font-bold text-slate-900">Contact Person</label>
                  <input 
                    required 
                    value={contactPerson} 
                    onChange={(e) => setContactPerson(e.target.value)} 
                    type="text" 
                    placeholder="Manager name" 
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500 transition text-sm font-medium" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-sm font-bold text-slate-900">Contact Phone</label>
                  <input 
                    required 
                    value={contactPhone} 
                    onChange={(e) => setContactPhone(e.target.value)} 
                    type="tel" 
                    placeholder="Phone number" 
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-blue-500 transition text-sm font-medium" 
