              <div className="flex gap-3 pt-4">
                <button 
                  type="button" 
                  onClick={handleCloseAddModal}
                  className="flex-1 py-3 border border-slate-200 text-slate-900 font-bold rounded-xl hover:bg-slate-50 transition"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-3 bg-slate-900 text-white font-bold rounded-xl hover:bg-slate-800 transition shadow-sm"
                >
                  Add Property
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
