                  <input required value={name} onChange={(e) => setName(e.target.value)} type="text" placeholder="e.g., Sunrise PG" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 transition text-sm font-bold" />
