                  <div className="relative">
                    <select value={type} onChange={(e) => setType(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 transition text-sm font-bold appearance-none pr-8">
                      <option value="Girls/Women">Girls/Women</option>
                      <option value="Boys">Boys</option>
