                  <input required value={rooms} onChange={(e) => setRooms(e.target.value)} type="number" placeholder="Count" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-blue-500/10 focus:border-blue-500 transition text-sm font-bold" />
                </div>
              </div>

              <div className="flex gap-4 pt-6">
                <button 
                  type="button" 
                  onClick={handleCloseAddModal}
                  className="flex-1 py-4 border border-slate-100 text-slate-400 font-black uppercase tracking-widest text-xs rounded-xl hover:bg-slate-50 transition"
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white font-black uppercase tracking-widest text-xs rounded-xl hover:bg-blue-700 transition shadow-xl shadow-blue-100"
                >
                  Confirm Property
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

