import React, { useState } from 'react';
import { UserRole } from '../types';
import { db } from '../services/mockData';

interface SignupProps {
  onSignupSuccess: (role: UserRole, userId: string) => void;
  onNavigateToLogin: () => void;
}

type SignupStep = 'form' | 'verify' | 'success';

const Signup: React.FC<SignupProps> = ({ onSignupSuccess, onNavigateToLogin }) => {
  const [role, setRole] = useState<UserRole>(UserRole.OWNER);
  const [step, setStep] = useState<SignupStep>('form');

  // Form Fields
  const [yourEmail, setYourEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState('');
  const [error, setError] = useState('');

  const handleSignUpClick = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // 1. Basic Validations
    if (password !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }

    if (username.length < 3) {
      setError('Username must be at least 3 characters.');
      return;
    }

    // 2. Check for Unique Username
    if (db.isUsernameTaken(username)) {
      setError('This username is already taken. Please choose another one.');
      return;
    }

    // 3. Check for Duplicate User Email
    if (db.isEmailRegisteredAsUser(yourEmail)) {
      setError('This email is already registered. Try logging in.');
      return;
    }

    // 4. Role-Specific Restriction: Staff and Resident must be pre-added by an Owner
    if (role !== UserRole.OWNER) {
      const residents = db.getResidents();
      const staff = db.getStaff();

      const resRecord = residents.find(r => r.email.toLowerCase() === yourEmail.toLowerCase());
      const staffRecord = staff.find(s => s.email.toLowerCase() === yourEmail.toLowerCase());

      if (role === UserRole.RESIDENT) {
        if (!resRecord) {
          setError("Access Denied: You must be added as a Resident by your property owner before you can sign up.");
          return;
        }
      }

      if (role === UserRole.STAFF) {
        if (!staffRecord) {
          setError("Access Denied: You must be added as a Staff member by the owner before you can sign up.");
          return;
        }
      }
    }

    setStep('verify');
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (otp === '123456') { 
      const userId = `USR-${Math.random().toString(36).substr(2, 9).toUpperCase()}`;

      // Double check username again at the moment of persistence to prevent race conditions in mock
      if (db.isUsernameTaken(username)) {
        setError('Someone just took that username! Please go back and pick another.');
        setStep('form');
        return;
      }

      // Persist the user
      db.saveUser({
        id: userId,
        username: username.toLowerCase(),
        email: yourEmail.toLowerCase(),
        password,
        role,
        createdAt: new Date().toISOString()
      });

      setStep('success');
      setTimeout(() => {
        onSignupSuccess(role, userId);
      }, 1500);
    } else {
      setError('Invalid OTP. Use 123456 for demo.');
    }
  };

  if (step === 'verify') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl p-10 border border-slate-100 animate-in fade-in zoom-in duration-300">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-blue-600 rounded-3xl mx-auto flex items-center justify-center text-white mb-6 shadow-xl shadow-blue-100">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
            </div>
            <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tight leading-none mb-3">Check Your Inbox</h2>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Verification code sent to <br/><span className="text-blue-600 lowercase tracking-normal">{yourEmail}</span></p>
          </div>

          <form onSubmit={handleVerifyOtp} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">6-Digit PIN</label>
              <input 
                type="text" 
                maxLength={6}
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                className="w-full text-center tracking-[0.8em] text-3xl font-black py-5 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all"
                placeholder="000000"
              />
            </div>
            {error && <p className="text-xs font-bold text-rose-600 text-center bg-rose-50 p-3 rounded-xl">{error}</p>}
            <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black uppercase tracking-widest text-xs rounded-2xl shadow-xl shadow-blue-100 hover:bg-blue-700 transition">
              Complete Profile Setup
            </button>
            <div className="text-center pt-2">
               <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest italic">Mock PIN: 123456</p>
            </div>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'success') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl p-16 text-center animate-in zoom-in duration-500">
          <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-[2rem] mx-auto flex items-center justify-center mb-8 border border-emerald-100">
            <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tight mb-2">Authenticated!</h2>
          <p className="text-slate-500 font-medium italic">Redirecting to your personalized workspace...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-blue-600 rounded-[2rem] mx-auto flex items-center justify-center text-white text-4xl font-black mb-6 shadow-2xl shadow-blue-200">H</div>
          <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tight leading-none">Create Account</h1>
          <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-2 italic opacity-60">Complete your onboarding process</p>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/50 p-10 border border-slate-100">
          <div className="flex bg-slate-50 p-1.5 rounded-2xl mb-8">
            {[UserRole.OWNER, UserRole.STAFF, UserRole.RESIDENT].map(r => (
              <button
                key={r}
                type="button"
                onClick={() => { setRole(r); setError(''); }}
                className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${role === r ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {r}
              </button>
            ))}
          </div>

          <form onSubmit={handleSignUpClick} className="space-y-5">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Address</label>
              <input 
                type="email" 
                value={yourEmail}
                onChange={(e) => setYourEmail(e.target.value)}
                className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all text-sm font-bold" 
                placeholder="registered@email.com"
                required
              />
              {role !== UserRole.OWNER && (
                <p className="text-[10px] text-blue-500 font-bold italic mt-1 px-1">
                  * Must use the email provided to your Hostel Owner.
                </p>
              )}
            </div>

            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Unique Username</label>
              <input 
                type="text" 
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all text-sm font-bold" 
                placeholder="e.g. rahul_hostel"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all text-sm font-bold" 
                  placeholder="••••••••"
                  required
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Confirm</label>
                <input 
                  type="password" 
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all text-sm font-bold" 
                  placeholder="••••••••"
                  required
                />
              </div>
            </div>

            {error && <p className="text-xs font-bold text-rose-600 bg-rose-50 p-3 rounded-xl border border-rose-100">{error}</p>}

            <button type="submit" className="w-full py-4 bg-blue-600 text-white font-black uppercase tracking-widest text-xs rounded-2xl shadow-xl shadow-blue-100 hover:bg-blue-700 transition active:scale-95">
              Secure My Profile
            </button>
          </form>

          <div className="mt-10 pt-8 border-t border-slate-50 text-center">
            <p className="text-sm font-bold text-slate-500">
              Already configured? {' '}
              <button onClick={onNavigateToLogin} className="text-blue-600 font-black uppercase tracking-widest text-xs hover:underline ml-1">Sign in</button>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

