import React, { useState } from 'react';
import { SubscriptionTier, PLAN_LIMITS } from '../types';
import { formatCurrency } from '../constants';

interface PlanSelectionProps {
  onSelect: (tier: SubscriptionTier) => void;
  currentTier?: SubscriptionTier;
}

const PlanSelection: React.FC<PlanSelectionProps> = ({ onSelect, currentTier }) => {
  const [billingCycle, setBillingCycle] = useState<'monthly' | 'annual'>('monthly');
  const [isProcessing, setIsProcessing] = useState(false);
  const [paymentStep, setPaymentStep] = useState<'none' | 'checkout' | 'processing'>('none');
  const [selectedTier, setSelectedTier] = useState<SubscriptionTier | null>(null);

  const plans = [
    {
      tier: SubscriptionTier.FREE,
      name: 'Free Starter',
      description: 'Ideal for small property trials.',
      features: ['1 Property', '2 Staff Members', '10 Residents', 'Basic Management'],
      highlight: false
    },
    {
      tier: SubscriptionTier.STANDARD,
      name: 'Standard',
      description: 'The sweet spot for growing hostels.',
      features: ['3 Properties', '15 Staff Members', '130 Residents', 'Monthly Reports', 'Priority Support'],
      highlight: true
    },
    {
      tier: SubscriptionTier.PRO,
      name: 'Pro Pack',
      description: 'Advanced tools for professionals.',
      features: ['10 Properties', '60 Staff Members', '600 Residents', 'Full Financial Reports', 'Data Export', 'Custom Permissions'],
      highlight: false
    },
    {
      tier: SubscriptionTier.ENTERPRISE,
      name: 'Enterprise',
      description: 'Tailored for hostel chains.',
      features: ['Unlimited Everything', 'Dedicated Success Manager', 'White-labeling', 'API Access', 'SSO Integration'],
      highlight: false
    }
