  const handleInitialSelect = (tier: SubscriptionTier) => {
    if (tier === SubscriptionTier.FREE) {
      onSelect(tier);
    } else {
      setSelectedTier(tier);
      setPaymentStep('checkout');
    }
  };

  const handleConfirmPayment = () => {
    setPaymentStep('processing');
    // Simulate Razorpay/Stripe Processing
    setTimeout(() => {
      if (selectedTier) {
        onSelect(selectedTier);
      }
    }, 2500);
  };

  return (
    <div className="bg-slate-50 min-h-screen p-8 md:p-16 animate-in fade-in duration-700 relative">
