              <div className="mb-10">
                <h3 className="text-2xl font-black text-slate-900 mb-2 uppercase tracking-tight">{p.name}</h3>
                <p className="text-slate-400 text-xs font-bold leading-relaxed">{p.description}</p>
              </div>

              <div className="mb-10 flex items-baseline gap-1.5">
                <span className="text-5xl font-black text-slate-900">{formatCurrency(displayPrice)}</span>
                <span className="text-slate-400 text-xs font-black uppercase tracking-widest">/ Month</span>
