              <div className="flex-1 space-y-5 mb-10">
                {p.features.map((f, idx) => (
                  <div key={idx} className="flex items-center gap-4">
                    <div className="w-6 h-6 rounded-xl bg-emerald-50 border border-emerald-100 flex items-center justify-center text-emerald-600">
                       <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" /></svg>
                    </div>
                    <span className="text-[11px] font-black text-slate-600 uppercase tracking-tight">{f}</span>
                  </div>
                ))}
              </div>

              <button 
                onClick={() => !isCurrent && handleInitialSelect(p.tier)}
                disabled={isCurrent}
                className={`w-full py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all duration-300 ${
                  isCurrent 
                    ? 'bg-emerald-50 text-emerald-600 border-2 border-emerald-200 cursor-default'
                    : p.highlight 
                      ? 'bg-blue-600 text-white shadow-xl shadow-blue-100 hover:bg-blue-700' 
