                }`}
              >
                {isCurrent ? 'Current Plan' : p.tier === SubscriptionTier.FREE ? 'Start Free' : 'Pay & Subscribe'}
              </button>
            </div>
          );
        })}
      </div>
      <div className="text-center mt-12">
        <p className="text-slate-400 text-xs font-bold italic">By subscribing, you agree to our Terms of Service and automated billing policy.</p>
      </div>
    </div>
  );
};

