                <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-full mx-auto flex items-center justify-center mb-10 border-4 border-emerald-100 shadow-xl shadow-emerald-100/50">
                  <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" /></svg>
                </div>
                <h3 className="text-2xl font-black text-slate-900 uppercase tracking-tight mb-2">Payment Confirmed!</h3>
                <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Your account is being upgraded...</p>
              </div>
            )}
          </div>
        </div>
      )}

      <div className="max-w-7xl mx-auto text-center mb-20">
        <h1 className="text-4xl md:text-6xl font-black text-slate-900 mb-6 uppercase tracking-tighter">Choose Your Power</h1>
        <p className="text-slate-500 text-lg max-w-2xl mx-auto font-medium">Select a plan to unlock advanced hostel automation tools.</p>

        <div className="mt-12 flex items-center justify-center gap-6">
           <span className={`text-[10px] font-black uppercase tracking-widest ${billingCycle === 'monthly' ? 'text-slate-900' : 'text-slate-400'}`}>Monthly</span>
           <button 
             onClick={() => setBillingCycle(billingCycle === 'monthly' ? 'annual' : 'monthly')}
             className="w-16 h-8 bg-slate-200 rounded-full relative p-1.5 transition-all hover:bg-slate-300"
           >
             <div className={`w-5 h-5 bg-blue-600 rounded-full shadow-lg transform transition-transform duration-300 ${billingCycle === 'annual' ? 'translate-x-8' : 'translate-x-0'}`}></div>
           </button>
           <span className={`text-[10px] font-black uppercase tracking-widest ${billingCycle === 'annual' ? 'text-slate-900' : 'text-slate-400'}`}>
             Annual <span className="text-emerald-500 ml-1.5 bg-emerald-50 px-2 py-1 rounded-lg border border-emerald-100">-20%</span>
           </span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-8">
        {plans.map((p) => {
          const limit = PLAN_LIMITS[p.tier];
          const isCurrent = currentTier === p.tier;
          const displayPrice = billingCycle === 'annual' ? Math.floor(limit.price * 0.8) : limit.price;

          return (
            <div 
              key={p.tier} 
              className={`relative flex flex-col p-10 rounded-[3rem] border-2 transition-all duration-500 hover:-translate-y-2 ${
                p.highlight 
                  ? 'border-blue-600 shadow-2xl shadow-blue-100 z-10 bg-white' 
                  : 'border-transparent bg-white/70 shadow-xl shadow-slate-100 hover:bg-white hover:border-blue-100'
              }`}
            >
              {p.highlight && (
                <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-blue-600 text-white px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest shadow-xl shadow-blue-200">
                  Most Popular
                </div>
              )}

              <div className="mb-10">
                <h3 className="text-2xl font-black text-slate-900 mb-2 uppercase tracking-tight">{p.name}</h3>
                <p className="text-slate-400 text-xs font-bold leading-relaxed h-8">{p.description}</p>
              </div>

              <div className="mb-10 flex items-baseline gap-1.5">
                <span className="text-5xl font-black text-slate-900 tracking-tighter">{formatCurrency(displayPrice)}</span>
                <span className="text-slate-400 text-[10px] font-black uppercase tracking-widest">/ mo</span>
              </div>

              <div className="flex-1 space-y-5 mb-10">
                {p.features.map((f, idx) => (
                  <div key={idx} className="flex items-center gap-4">
                    <div className="w-5 h-5 rounded-lg bg-emerald-50 border border-emerald-100 flex items-center justify-center text-emerald-600 shrink-0">
                       <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" /></svg>
                    </div>
                    <span className="text-[10px] font-black text-slate-600 uppercase tracking-tight">{f}</span>
                  </div>
                ))}
              </div>

              <button 
                onClick={() => !isCurrent && handleInitialSelect(p.tier)}
                disabled={isCurrent}
                className={`w-full py-5 rounded-2xl font-black uppercase tracking-widest text-xs transition-all duration-300 ${
                  isCurrent 
                    ? 'bg-emerald-50 text-emerald-600 border-2 border-emerald-200 cursor-default'
                    : p.highlight 
                      ? 'bg-blue-600 text-white shadow-xl shadow-blue-100 hover:bg-blue-700 active:scale-95' 
                      : 'bg-blue-50 text-blue-600 border-2 border-blue-50 hover:bg-blue-600 hover:text-white hover:border-blue-600 shadow-sm active:scale-95'
                }`}
              >
                {isCurrent ? 'Current Plan' : p.tier === SubscriptionTier.FREE ? 'Get Started' : 'Upgrade Now'}
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default PlanSelection;

import React, { useState } from 'react';
import { UserRole } from '../types';
import { db } from '../services/mockData';

interface SignupProps {
  onSignupSuccess: (role: UserRole, userId: string) => void;
  onNavigateToLogin: () => void;
}

type SignupStep = 'form' | 'verify' | 'success';

const Signup: React.FC<SignupProps> = ({ onSignupSuccess, onNavigateToLogin }) => {
  const [role, setRole] = useState<UserRole>(UserRole.OWNER);
  const [step, setStep] = useState<SignupStep>('form');

  // Form Fields
  const [yourEmail, setYourEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [otp, setOtp] = useState('');
  const [error, setError] = useState('');

  const handleSignUpClick = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // 1. Basic Validations
    if (password !== confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    if (password.length < 6) {
      setError('Password must be at least 6 characters.');
      return;
    }

    if (username.length < 3) {
      setError('Username must be at least 3 characters.');
      return;
    }

    // 2. Check for Unique Username (MANDATORY)
    if (db.isUsernameTaken(username)) {
      setError(`Username "${username}" is already in use. Please choose a unique identifier.`);
      return;
    }

    // 3. Check for Duplicate User Email
    if (db.isEmailRegisteredAsUser(yourEmail)) {
      setError('An account with this email already exists. Try signing in.');
      return;
    }

    // 4. Role-Specific Restriction: Staff and Resident must be pre-added by an Owner
    if (role !== UserRole.OWNER) {
      const residents = db.getResidents();
      const staffList = db.getStaff();

      const resRecord = residents.find(r => r.email.toLowerCase() === yourEmail.toLowerCase());
      const staffRecord = staffList.find(s => s.email.toLowerCase() === yourEmail.toLowerCase());

      if (role === UserRole.RESIDENT) {
        if (!resRecord) {
          setError("Verification Failed: Your email isn't registered in any hostel. Ask your Owner to add you first.");
          return;
        }
      }

      if (role === UserRole.STAFF) {
        if (!staffRecord) {
          setError("Verification Failed: Staff registration requires pre-approval. Contact your property manager.");
          return;
        }
      }
    }

    setStep('verify');
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (otp === '123456') { 
      const userId = `USR-${Math.random().toString(36).substr(2, 9).toUpperCase()}`;

      // Final persistence check for username uniqueness
      if (db.isUsernameTaken(username)) {
        setError('Username was just taken! Please go back and choose another.');
        setStep('form');
        return;
      }

      // Persist the user
      db.saveUser({
        id: userId,
        username: username.toLowerCase().trim(),
        email: yourEmail.toLowerCase().trim(),
        password,
        role,
        createdAt: new Date().toISOString()
      });

      setStep('success');
      setTimeout(() => {
        onSignupSuccess(role, userId);
      }, 1500);
    } else {
      setError('Invalid verification code. Use 123456.');
    }
  };

  if (step === 'verify') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl p-12 border border-slate-100 animate-in fade-in zoom-in duration-300">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-blue-600 rounded-[2rem] mx-auto flex items-center justify-center text-white mb-6 shadow-2xl shadow-blue-100">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
              </svg>
            </div>
            <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tight mb-2">Verify Email</h2>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Code sent to: <span className="text-blue-600 tracking-normal lowercase font-bold">{yourEmail}</span></p>
          </div>

          <form onSubmit={handleVerifyOtp} className="space-y-8">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Authentication PIN</label>
              <input 
                type="text" 
                maxLength={6}
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                className="w-full text-center tracking-[1em] text-4xl font-black py-6 bg-slate-50 border-2 border-slate-100 rounded-3xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all"
                placeholder="000000"
              />
            </div>
            {error && <p className="text-xs font-bold text-rose-600 text-center bg-rose-50 p-4 rounded-2xl border border-rose-100">{error}</p>}
            <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black uppercase tracking-widest text-xs rounded-2xl shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all hover:-translate-y-1">
              Verify & Complete Signup
            </button>
            <p className="text-center text-[10px] font-black text-slate-300 uppercase tracking-tight italic">Demo Key: 123456</p>
          </form>
        </div>
      </div>
    );
  }

  if (step === 'success') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="w-full max-w-md bg-white rounded-[3.5rem] shadow-2xl p-20 text-center animate-in zoom-in duration-500 border border-slate-50">
          <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-[2.5rem] mx-auto flex items-center justify-center mb-8 border-4 border-emerald-100 shadow-xl shadow-emerald-50">
            <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
            </svg>
          </div>
          <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter mb-2">Welcome!</h2>
          <p className="text-slate-500 font-bold italic text-sm">Synchronizing your dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="w-full max-w-lg">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-blue-600 rounded-[2rem] mx-auto flex items-center justify-center text-white text-4xl font-black mb-6 shadow-2xl shadow-blue-200">H</div>
          <h1 className="text-4xl font-black text-slate-900 uppercase tracking-tighter">Get Started</h1>
          <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-2 italic opacity-60">Join the world's leading hostel network</p>
        </div>

        <div className="bg-white rounded-[3rem] shadow-2xl shadow-slate-200/50 p-12 border border-slate-100 relative overflow-hidden group">
          <div className="flex bg-slate-50 p-1.5 rounded-2xl mb-10 border border-slate-100">
            {[UserRole.OWNER, UserRole.STAFF, UserRole.RESIDENT].map(r => (
              <button
                key={r}
                type="button"
                onClick={() => { setRole(r); setError(''); }}
                className={`flex-1 py-3.5 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${role === r ? 'bg-white text-blue-600 shadow-md border border-slate-100' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {r}
              </button>
            ))}
          </div>

          <form onSubmit={handleSignUpClick} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Address</label>
              <input 
                type="email" 
                value={yourEmail}
                onChange={(e) => setYourEmail(e.target.value)}
                className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all text-sm font-bold" 
                placeholder="Enter your registered email"
                required
              />
              {role !== UserRole.OWNER && (
                <p className="text-[9px] text-blue-500 font-black italic mt-1.5 px-1 uppercase tracking-tighter">
                  * Note: Use the email registered by your hostel owner.
                </p>
              )}
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Unique Username</label>
              <input 
                type="text" 
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all text-sm font-bold" 
                placeholder="Pick a unique handle"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
                <input 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all text-sm font-bold" 
                  placeholder="••••••••"
                  required
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Repeat</label>
                <input 
                  type="password" 
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all text-sm font-bold" 
                  placeholder="••••••••"
                  required
                />
              </div>
            </div>

            {error && <p className="text-xs font-bold text-rose-600 bg-rose-50 p-4 rounded-2xl border border-rose-100 animate-shake">{error}</p>}

            <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black uppercase tracking-widest text-xs rounded-2xl shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all hover:-translate-y-1 active:scale-95 mt-4">
              Secure My Account
            </button>
          </form>

          <div className="mt-10 pt-8 border-t border-slate-50 text-center">
            <p className="text-sm font-bold text-slate-500">
              Already a member? {' '}
              <button onClick={onNavigateToLogin} className="text-blue-600 font-black uppercase tracking-widest text-xs hover:underline ml-1">Sign in</button>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Signup;

import React, { useState, useMemo } from 'react';
import { db } from '../services/mockData';
import { formatCurrency } from '../constants';
import { Resident, PLAN_LIMITS, Property, Unit, RoomStatus } from '../types';
import UpgradeModal from './UpgradeModal';

interface ResidentsProps {
  ownerId: string;
  onUpgrade: () => void;
}

const Residents: React.FC<ResidentsProps> = ({ ownerId, onUpgrade }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [residents, setResidents] = useState<Resident[]>(db.getResidents(ownerId));
  const [properties] = useState<Property[]>(db.getProperties(ownerId));
  const [units] = useState<Unit[]>(db.getUnits(ownerId));
  const [showAdd, setShowAdd] = useState(false);
  const [showUpgradeModal, setShowUpgradeModal] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [dob, setDob] = useState('');
  const [address, setAddress] = useState('');
  const [propertyId, setPropertyId] = useState('');
  const [roomNumber, setRoomNumber] = useState('');
  const [unitId, setUnitId] = useState('');
  const [moveInDate, setMoveInDate] = useState('');
  const [rent, setRent] = useState('');
  const [idProofType, setIdProofType] = useState('');
  const [idNumber, setIdNumber] = useState('');

  const user = db.getUsers().find((u: any) => u.id === ownerId);
  const plan = user?.plan ? PLAN_LIMITS[user.plan] : PLAN_LIMITS.FREE;

  // Filter units based on selected property
  const availableUnitsForProperty = useMemo(() => {
    if (!propertyId) return [];
    return units.filter(u => u.propertyId === propertyId);
  }, [propertyId, units]);

  const handleTryAdd = () => {
    if (plan.residents !== null && residents.length >= plan.residents) {
      setShowUpgradeModal(true);
      return;
    }
    setShowAdd(true);
  };

  const filteredResidents = residents.filter(r => 
    r.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    r.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDeleteResident = (id: string) => {
    if (window.confirm('Are you sure you want to remove this resident?')) {
      db.deleteResident(id);
      setResidents(db.getResidents(ownerId));
    }
  };

  const handleUnitChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const selectedUnitId = e.target.value;
    const unit = availableUnitsForProperty.find(u => u.id === selectedUnitId);
    if (unit) {
      setUnitId(unit.id);
      setRoomNumber(unit.roomNumber);
      // Auto-populate rent if unit has price
      if (unit.price) setRent(unit.price.toString());
    } else {
      setUnitId('');
      setRoomNumber('');
    }
  };

  const handleAddResident = (e: React.FormEvent) => {
    e.preventDefault();
    const newRes: Resident = {
      id: `RES-${Date.now()}`,
      ownerId,
      name,
      email,
      phone,
      dob,
      permanentAddress: address,
      unitId: unitId,
      propertyId,
      roomNumber,
      moveInDate,
      dueDate: 5, // Default due date
      status: 'active',
      rent: parseInt(rent) || 0,
      idProofType,
      idNumber
    };
    db.saveResident(newRes);
    setResidents(db.getResidents(ownerId));
    setShowAdd(false);
    // Reset form
    setName(''); setEmail(''); setPhone(''); setDob(''); setAddress('');
    setPropertyId(''); setRoomNumber(''); setUnitId(''); setMoveInDate(''); setRent('');
    setIdProofType(''); setIdNumber('');
  };

  const getUnitStatusLabel = (u: Unit) => {
    if (u.status === RoomStatus.MAINTENANCE) return 'Maintenance';
    if (u.currentOccupants === 0) return 'Vacant';
    if (u.currentOccupants < u.capacity) return 'Partial';
    return 'Full';
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Residents</h1>
          <p className="text-slate-500 font-medium">Add placeholders so your residents can sign up.</p>
        </div>
        <button 
          onClick={handleTryAdd}
          className="bg-blue-600 text-white px-6 py-3 rounded-xl font-black uppercase tracking-widest text-xs hover:bg-blue-700 transition shadow-xl shadow-blue-100"
        >
          + Add Resident
        </button>
      </div>

      <UpgradeModal 
        isOpen={showUpgradeModal}
        onClose={() => setShowUpgradeModal(false)}
        onUpgrade={() => {
          setShowUpgradeModal(false);
          onUpgrade();
        }}
        limitType="residents"
        limitValue={plan.residents || 0}
      />

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 p-8">
        <div className="relative mb-10">
          <svg className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <input 
            type="text" 
            placeholder="Search email or name..." 
            className="w-full pl-14 pr-8 py-5 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:bg-white focus:border-blue-500 transition-all font-bold text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto">
          {residents.length === 0 ? (
            <div className="py-24 text-center">
               <div className="w-20 h-20 bg-slate-50 rounded-full mx-auto flex items-center justify-center text-slate-200 mb-4">
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
               </div>
               <p className="text-slate-400 font-bold italic">No resident records found.</p>
            </div>
          ) : (
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-6 py-6">Profile</th>
                  <th className="px-6 py-6">Room</th>
                  <th className="px-6 py-6">Rent Info</th>
                  <th className="px-6 py-6">Status</th>
                  <th className="px-6 py-6 text-right">Manage</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredResidents.map((r) => (
                  <tr key={r.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-6 py-8">
                      <div className="flex items-center gap-5">
                        <div className="w-12 h-12 rounded-2xl bg-slate-100 flex items-center justify-center font-black text-slate-400 text-base">{r.name[0]}</div>
                        <div>
                          <p className="font-black text-slate-900 leading-none mb-1">{r.name}</p>
                          <p className="text-xs font-bold text-slate-400 lowercase">{r.email}</p>
