import React, { useState, useEffect } from 'react';
import { UserRole, SubscriptionTier } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Properties from './components/Properties';
import Residents from './components/Residents';
import Payments from './components/Payments';
import Complaints from './components/Complaints';
import Rooms from './components/Rooms';
import SuperAdmin from './components/SuperAdmin';
import ResidentApp from './components/ResidentApp';
import Login from './components/Login';
import Signup from './components/Signup';
import PlanSelection from './components/PlanSelection';
import { db } from './services/mockData';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isSigningUp, setIsSigningUp] = useState(false);
  const [currentRole, setCurrentRole] = useState<UserRole>(UserRole.OWNER);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<string>('dashboard');
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [impersonatingOwner, setImpersonatingOwner] = useState<string | null>(null);
  const [showPlanSelection, setShowPlanSelection] = useState(false);
  const [forceOpenPropertyModal, setForceOpenPropertyModal] = useState(false);
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);

  useEffect(() => {
    // Seed the database if it's the first time
    db.seed();

    const handleResize = () => {
      if (window.innerWidth < 1024) setSidebarOpen(false);
      else setSidebarOpen(true);
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const getCurrentUser = () => {
    if (!currentUserId) return null;
    return db.getUsers().find((u: any) => u.id === currentUserId);
  };

  const user = getCurrentUser();

  const handleLoginSuccess = (role: UserRole, userId: string) => {
    setCurrentRole(role);
    setCurrentUserId(userId);
    setIsAuthenticated(true);
    setActiveTab('dashboard');

    // Check if owner needs to pick a plan
    if (role === UserRole.OWNER) {
      const u = db.getUsers().find((usr: any) => usr.id === userId);
      if (!u?.plan) {
        setShowPlanSelection(true);
      }
    }
  };

  const handleSignupSuccess = (role: UserRole, userId: string) => {
    setCurrentRole(role);
    setCurrentUserId(userId);
    setIsAuthenticated(true);
    setActiveTab('dashboard');
    if (role === UserRole.OWNER) {
      setShowPlanSelection(true);
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUserId(null);
    setImpersonatingOwner(null);
    setShowPlanSelection(false);
  };

  const handlePlanSelect = (tier: SubscriptionTier) => {
    if (currentUserId) {
      db.updateUserPlan(currentUserId, tier);
      setShowPlanSelection(false);
    }
  };

  const handleAddPropertyFromDash = () => {
    setActiveTab('properties');
    setForceOpenPropertyModal(true);
  };

  const handleManageRooms = (propertyId: string) => {
    setSelectedPropertyId(propertyId);
    setActiveTab('rooms');
  };

  if (!isAuthenticated) {
    if (isSigningUp) {
      return <Signup onSignupSuccess={handleSignupSuccess} onNavigateToLogin={() => setIsSigningUp(false)} />;
    }
    return <Login onLogin={handleLoginSuccess} onNavigateToSignup={() => setIsSigningUp(true)} />;
  }

  if (showPlanSelection) {
    return <PlanSelection onSelect={handlePlanSelect} currentTier={user?.plan} />;
  }

  const effectiveOwnerId = impersonatingOwner || (currentRole === UserRole.OWNER ? currentUserId : null);

  const renderContent = () => {
    if (currentRole === UserRole.SUPERADMIN && !impersonatingOwner) {
      return <SuperAdmin onImpersonate={(ownerId) => {
        setImpersonatingOwner(ownerId);
        setCurrentRole(UserRole.OWNER);
        setActiveTab('dashboard');
      }} />;
    }

    if (currentRole === UserRole.RESIDENT) {
      const resId = currentUserId || '';
      if (activeTab === 'dashboard') return <ResidentApp residentId={resId} />;
      if (activeTab === 'payments') return <Payments ownerId={effectiveOwnerId || ''} />;
      if (activeTab === 'complaints') return <Complaints role={currentRole} ownerId={effectiveOwnerId || ''} />;
      return <ResidentApp residentId={resId} />;
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard role={currentRole} ownerId={effectiveOwnerId || ''} onAddProperty={handleAddPropertyFromDash} />;
      case 'properties': return (
        <Properties 
          ownerId={effectiveOwnerId || ''} 
          onUpgrade={() => setShowPlanSelection(true)} 
          forceOpenModal={forceOpenPropertyModal}
          onModalClose={() => setForceOpenPropertyModal(false)}
          onManageRooms={handleManageRooms}
        />
      );
      case 'rooms': return (
        <Rooms 
          ownerId={effectiveOwnerId || ''} 
          initialPropertyId={selectedPropertyId} 
          onUpgrade={() => setShowPlanSelection(true)} 
        />
      );
      case 'residents': return <Residents ownerId={effectiveOwnerId || ''} onUpgrade={() => setShowPlanSelection(true)} />;
      case 'payments': return <Payments ownerId={effectiveOwnerId || ''} />;
      case 'complaints': return <Complaints role={currentRole} ownerId={effectiveOwnerId || ''} />;
      case 'expenses': return (
        <div className="p-12 text-center text-slate-400">
           <div className="w-16 h-16 bg-slate-100 rounded-full mx-auto mb-4 flex items-center justify-center text-xl">INR</div>
           <h3 className="font-bold text-slate-900">Expenses Tracker</h3>
           <p className="max-w-xs mx-auto mt-2">Daily expense recording. (Coming Soon)</p>
        </div>
      );
      case 'superadmin': return <SuperAdmin onImpersonate={setImpersonatingOwner} />;
      default: return <Dashboard role={currentRole} ownerId={effectiveOwnerId || ''} onAddProperty={handleAddPropertyFromDash} />;
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      {impersonatingOwner && (
        <div className="fixed top-0 left-0 right-0 bg-rose-600 text-white text-center py-2 z-[60] font-bold text-[10px] uppercase tracking-widest flex justify-between px-6 items-center shadow-lg">
          <span>SUPERADMIN ACCESS: VIEWING OWNER <strong>{impersonatingOwner}</strong></span>
          <button 
            onClick={() => {
              setImpersonatingOwner(null);
              setCurrentRole(UserRole.SUPERADMIN);
              setActiveTab('superadmin');
            }}
            className="bg-white text-rose-600 px-3 py-1 rounded-full text-[10px] hover:bg-rose-50 transition"
          >
            Exit Impersonation
          </button>
        </div>
      )}

      <Sidebar 
        isOpen={isSidebarOpen} 
        setOpen={setSidebarOpen} 
        activeTab={activeTab} 
        setActiveTab={setActiveTab}
        role={currentRole}
        planTier={user?.plan}
      />

      <div className={`flex-1 flex flex-col transition-all duration-300 ${isSidebarOpen ? 'lg:ml-64' : 'ml-0'} ${impersonatingOwner ? 'pt-10' : ''}`}>
        <Header 
          toggleSidebar={() => setSidebarOpen(!isSidebarOpen)} 
          role={currentRole}
          onLogout={handleLogout}
        />
        <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-10">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { db } from '../services/mockData';
import { formatCurrency } from '../constants';
import { Unit, Property, RoomStatus } from '../types';

interface RoomsProps {
  ownerId: string;
  initialPropertyId: string | null;
  onUpgrade: () => void;
}

const Rooms: React.FC<RoomsProps> = ({ ownerId, initialPropertyId, onUpgrade }) => {
  const [properties] = useState<Property[]>(db.getProperties(ownerId));
  const [selectedPropId, setSelectedPropId] = useState<string>(initialPropertyId || 'all');
  const [units, setUnits] = useState<Unit[]>(db.getUnits(ownerId));

  // Modal States
  const [showAddModal, setShowAddModal] = useState(false);
  const [showViewModal, setShowViewModal] = useState(false);
  const [editingUnitId, setEditingUnitId] = useState<string | null>(null);
  const [viewingUnit, setViewingUnit] = useState<Unit | null>(null);

  // Status computation logic for table display
  const getUnitStatus = (u: Unit) => {
    if (u.status === RoomStatus.MAINTENANCE) return RoomStatus.MAINTENANCE;
    if (u.currentOccupants === 0) return RoomStatus.VACANT;
    if (u.currentOccupants < u.capacity) return RoomStatus.PARTIAL;
    return RoomStatus.FULL;
  };

  const filteredUnits = selectedPropId === 'all' 
    ? units 
    : units.filter(u => u.propertyId === selectedPropId);

  const stats = {
    total: filteredUnits.length,
    vacant: filteredUnits.filter(u => getUnitStatus(u) === RoomStatus.VACANT).length,
    occupied: filteredUnits.filter(u => getUnitStatus(u) === RoomStatus.FULL || getUnitStatus(u) === RoomStatus.PARTIAL).length,
    maintenance: filteredUnits.filter(u => getUnitStatus(u) === RoomStatus.MAINTENANCE).length,
  };

  // Add/Edit Room Form State
  const [formPropId, setFormPropId] = useState(initialPropertyId || '');
  const [roomNumber, setRoomNumber] = useState('');
  const [roomType, setRoomType] = useState('1'); // '1', '2', '3', '4', '5', 'custom'
  const [customShare, setCustomShare] = useState('');
  const [rent, setRent] = useState('');
  const [floor, setFloor] = useState('');
  const [isMaintenance, setIsMaintenance] = useState(false);
  const [amenities, setAmenities] = useState<Record<string, boolean>>({
    AC: false, WiFi: false, 'Attached Bath': false, Balcony: false, TV: false, Fridge: false
  });
  const [notes, setNotes] = useState('');

  const resetForm = () => {
    setFormPropId(initialPropertyId || '');
    setRoomNumber('');
    setRoomType('1');
    setCustomShare('');
    setRent('');
    setFloor('');
    setNotes('');
    setIsMaintenance(false);
    setAmenities({
      AC: false, WiFi: false, 'Attached Bath': false, Balcony: false, TV: false, Fridge: false
    });
    setEditingUnitId(null);
  };

  const handleEditClick = (u: Unit) => {
    setEditingUnitId(u.id);
    setFormPropId(u.propertyId);
    setRoomNumber(u.roomNumber);
    setFloor(u.floorNumber);
    setRent(u.price.toString());
    setNotes(u.notes || '');
    setIsMaintenance(u.status === RoomStatus.MAINTENANCE);

    const capacityVal = u.capacity.toString();
    if (['1', '2', '3', '4', '5'].includes(capacityVal)) {
      setRoomType(capacityVal);
    } else {
      setRoomType('custom');
      setCustomShare(capacityVal);
    }

    const newAmenities = { ...amenities };
    Object.keys(newAmenities).forEach(key => {
      newAmenities[key] = u.amenities.includes(key);
    });
    setAmenities(newAmenities);

    setShowAddModal(true);
  };

  const handleViewClick = (u: Unit) => {
    setViewingUnit(u);
    setShowViewModal(true);
  };

  const handleSubmitRoom = (e: React.FormEvent) => {
    e.preventDefault();
    const prop = properties.find(p => p.id === formPropId);
    const capacity = roomType === 'custom' ? parseInt(customShare) : parseInt(roomType);

    const unitData: Unit = {
      id: editingUnitId || `UNIT-${Date.now()}`,
      propertyId: formPropId,
      propertyName: prop?.name || 'Unknown',
      roomNumber,
      type: `${capacity}-share`,
      capacity: capacity || 1,
      currentOccupants: editingUnitId ? (units.find(u => u.id === editingUnitId)?.currentOccupants || 0) : 0,
      price: parseInt(rent) || 0,
      status: isMaintenance ? RoomStatus.MAINTENANCE : (editingUnitId ? (units.find(u => u.id === editingUnitId)?.status || RoomStatus.VACANT) : RoomStatus.VACANT),
      floorNumber: floor,
      amenities: Object.keys(amenities).filter(k => amenities[k]),
      tenantName: editingUnitId ? (units.find(u => u.id === editingUnitId)?.tenantName || '-') : '-',
      notes
    };

    if (editingUnitId) {
      db.updateUnit(unitData);
    } else {
      db.saveUnit(unitData);
    }

    setUnits(db.getUnits(ownerId));
    setShowAddModal(false);
    resetForm();
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Header & Filter */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight uppercase">Room Management</h1>
          <p className="text-slate-500 font-medium">Configure and monitor individual living units.</p>
        </div>
        <div className="flex items-center gap-4 w-full md:w-auto">
          <div className="relative flex-1 md:flex-none">
            <select 
              value={selectedPropId} 
              onChange={(e) => setSelectedPropId(e.target.value)}
              className="w-full md:w-56 px-4 py-3 bg-white border border-slate-200 rounded-xl text-xs font-black uppercase tracking-widest appearance-none pr-10 outline-none focus:ring-4 focus:ring-blue-500/5 focus:border-blue-500 transition-all shadow-sm"
            >
              <option value="all">All Properties</option>
              {properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
            <svg className="w-4 h-4 absolute right-3.5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
          </div>
          <button 
            onClick={() => { resetForm(); setShowAddModal(true); }}
            className="bg-blue-600 text-white px-6 py-3 rounded-xl font-black uppercase tracking-widest text-xs hover:bg-blue-700 transition-all flex items-center gap-3 shadow-xl shadow-blue-100 hover:-translate-y-0.5"
          >
            <span className="text-xl leading-none">+</span> Add Room
          </button>
        </div>
      </div>

      {/* Stats Section */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
        <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm text-center group hover:border-blue-100 transition-all">
          <p className="text-5xl font-black text-slate-900 mb-2 group-hover:scale-110 transition-transform">{stats.total}</p>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Inventory</p>
        </div>
        <div className="bg-emerald-50/50 p-8 rounded-[2rem] border border-emerald-100 shadow-sm text-center">
          <p className="text-5xl font-black text-emerald-600 mb-2">{stats.vacant}</p>
          <p className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">Available Now</p>
        </div>
        <div className="bg-blue-50/50 p-8 rounded-[2rem] border border-blue-100 shadow-sm text-center">
          <p className="text-5xl font-black text-blue-600 mb-2">{stats.occupied}</p>
          <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest">Occupied</p>
        </div>
        <div className="bg-orange-50/50 p-8 rounded-[2rem] border border-orange-100 shadow-sm text-center">
          <p className="text-5xl font-black text-orange-500 mb-2">{stats.maintenance}</p>
          <p className="text-[10px] font-black text-orange-400 uppercase tracking-widest">Maintenance</p>
        </div>
      </div>

      {/* Table Section */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-10 border-b border-slate-50 bg-slate-50/30">
          <h3 className="font-black text-slate-900 uppercase tracking-widest text-sm mb-1">Room Inventory Details</h3>
          <p className="text-slate-400 text-xs font-medium">Real-time status tracking for all units across {properties.length} properties</p>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/80 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                <th className="px-10 py-6">Room</th>
                <th className="px-10 py-6">Property</th>
                <th className="px-10 py-6">Type</th>
                <th className="px-10 py-6">Beds (Occ/Total)</th>
                <th className="px-10 py-6">Rent / Bed</th>
                <th className="px-10 py-6">Status</th>
                <th className="px-10 py-6">Current Tenant</th>
                <th className="px-10 py-6 text-right">Options</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredUnits.length === 0 ? (
                <tr>
                  <td colSpan={8} className="px-10 py-32 text-center">
                     <div className="max-w-xs mx-auto text-slate-300">
                        <svg className="w-12 h-12 mx-auto mb-4 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" /></svg>
                        <p className="font-bold italic">No room configurations found in this property group.</p>
                     </div>
                  </td>
                </tr>
              ) : (
                filteredUnits.map((u) => {
                  const status = getUnitStatus(u);
                  return (
                    <tr key={u.id} className="hover:bg-slate-50/50 transition-all group">
                      <td className="px-10 py-8">
                         <p className="font-black text-slate-900 text-base leading-tight mb-1">{u.roomNumber}</p>
