              <button onClick={() => setShowViewModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-600 transition">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
              <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tight">Room Details</h2>
              <p className="text-slate-500 text-sm mt-1 font-medium italic">Unit Information for Room {viewingUnit.roomNumber}</p>
            </div>

            <div className="p-10 space-y-8">
              <div className="grid grid-cols-2 gap-8">
                <div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Property Name</p>
                   <p className="font-bold text-slate-900 leading-snug">{viewingUnit.propertyName}</p>
                </div>
                <div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Room / Floor</p>
                   <p className="font-bold text-slate-900 leading-snug">{viewingUnit.roomNumber} (Floor {viewingUnit.floorNumber})</p>
                </div>
                <div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Unit Type</p>
                   <p className="font-bold text-slate-900 uppercase">{viewingUnit.type}</p>
                </div>
                <div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Beds</p>
                   <p className="font-bold text-slate-900">{viewingUnit.currentOccupants} Occupied / {viewingUnit.capacity} Total</p>
                </div>
                <div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Rent per Bed</p>
                   <p className="font-bold text-slate-900 text-xl leading-none mt-1">{formatCurrency(viewingUnit.price)}</p>
                </div>
                <div>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Status</p>
                   <span className={`inline-block px-3 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-wider mt-1 border whitespace-nowrap leading-none ${
                      getUnitStatus(viewingUnit) === RoomStatus.VACANT ? 'bg-emerald-50 text-emerald-600 border-emerald-100' :
                      getUnitStatus(viewingUnit) === RoomStatus.PARTIAL ? 'bg-blue-50 text-blue-600 border-blue-100' :
                      getUnitStatus(viewingUnit) === RoomStatus.FULL ? 'bg-slate-900 text-white border-slate-900' :
                      'bg-orange-50 text-orange-600 border-orange-100'
                    }`}>
                      {getUnitStatus(viewingUnit)}
                    </span>
                </div>
