import React, { useState, useMemo } from 'react';
import { db } from '../services/mockData';
import { formatCurrency } from '../constants';
import { Resident, PLAN_LIMITS, Property, Unit, RoomStatus } from '../types';
import UpgradeModal from './UpgradeModal';

interface ResidentsProps {
  ownerId: string;
  onUpgrade: () => void;
}

const Residents: React.FC<ResidentsProps> = ({ ownerId, onUpgrade }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [residents, setResidents] = useState<Resident[]>(db.getResidents(ownerId));
  const [properties] = useState<Property[]>(db.getProperties(ownerId));
  const [units, setUnits] = useState<Unit[]>(db.getUnits(ownerId));
  const [showAdd, setShowAdd] = useState(false);
  const [showUpgradeModal, setShowUpgradeModal] = useState(false);

  // Move Resident Modal State
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [selectedResidentForMove, setSelectedResidentForMove] = useState<Resident | null>(null);
  const [targetUnitId, setTargetUnitId] = useState('');

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [dob, setDob] = useState('');
  const [address, setAddress] = useState('');
  const [propertyId, setPropertyId] = useState('');
  const [roomNumber, setRoomNumber] = useState('');
  const [unitId, setUnitId] = useState('');
  const [moveInDate, setMoveInDate] = useState('');
  const [rent, setRent] = useState('');
  const [idProofType, setIdProofType] = useState('');
  const [idNumber, setIdNumber] = useState('');

  const user = db.getUsers().find((u: any) => u.id === ownerId);
  const plan = user?.plan ? PLAN_LIMITS[user.plan] : PLAN_LIMITS.FREE;

  // Filter units based on selected property
  const availableUnitsForProperty = useMemo(() => {
    if (!propertyId) return [];
    return units.filter(u => u.propertyId === propertyId);
  }, [propertyId, units]);

  // Prorated Calculation Helpers
  const getProratedInfo = (resident: Resident, targetUnit: Unit) => {
    const now = new Date();
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
    const currentDay = now.getDate();

    const daysSpent = currentDay;
    const remainingDays = daysInMonth - daysSpent;

    const oldDaily = resident.rent / daysInMonth;
    const newDaily = targetUnit.price / daysInMonth;

    const oldCost = oldDaily * daysSpent;
    const newCost = newDaily * remainingDays;
    const totalAdjusted = oldCost + newCost;

    return {
      daysInMonth,
      currentDay,
      daysSpent,
      remainingDays,
      oldCost,
      newCost,
      totalAdjusted,
      oldRent: resident.rent,
      newRent: targetUnit.price
    };
  };

  const handleTryAdd = () => {
    if (plan.residents !== null && residents.length >= plan.residents) {
      setShowUpgradeModal(true);
      return;
    }
    setShowAdd(true);
  };

  const filteredResidents = residents.filter(r => 
    r.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    r.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDeleteResident = (id: string) => {
    if (window.confirm('Are you sure you want to remove this resident?')) {
      db.deleteResident(id);
      setResidents(db.getResidents(ownerId));
    }
  };

  const handleMoveResident = () => {
    if (!selectedResidentForMove || !targetUnitId) return;

    const targetUnit = units.find(u => u.id === targetUnitId);
    const oldUnitId = selectedResidentForMove.unitId;

    if (targetUnit) {
      // 1. Update target unit occupants
      const updatedTarget: Unit = {
        ...targetUnit,
        currentOccupants: targetUnit.currentOccupants + 1,
        status: (targetUnit.currentOccupants + 1) >= targetUnit.capacity ? RoomStatus.FULL : RoomStatus.PARTIAL
      };
      db.updateUnit(updatedTarget);

      // 2. Update old unit occupants
      const oldUnit = units.find(u => u.id === oldUnitId);
      if (oldUnit) {
        const updatedOld: Unit = {
          ...oldUnit,
          currentOccupants: Math.max(0, oldUnit.currentOccupants - 1),
          status: (oldUnit.currentOccupants - 1) === 0 ? RoomStatus.VACANT : RoomStatus.PARTIAL
        };
        db.updateUnit(updatedOld);
      }

      // 3. Update resident details
      const updatedResident: Resident = {
        ...selectedResidentForMove,
        unitId: targetUnit.id,
        roomNumber: targetUnit.roomNumber,
        rent: targetUnit.price // Update to new room rent
      };
      db.updateResident(updatedResident);

      // Refresh state
      setResidents(db.getResidents(ownerId));
      setUnits(db.getUnits(ownerId));
      setShowMoveModal(false);
      setSelectedResidentForMove(null);
      setTargetUnitId('');
    }
  };

  const handleUnitChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const selectedUnitId = e.target.value;
    const unit = availableUnitsForProperty.find(u => u.id === selectedUnitId);
    if (unit) {
      setUnitId(unit.id);
      setRoomNumber(unit.roomNumber);
      if (unit.price) setRent(unit.price.toString());
    } else {
      setUnitId('');
      setRoomNumber('');
    }
  };

  const handleAddResident = (e: React.FormEvent) => {
    e.preventDefault();
    const newRes: Resident = {
      id: `RES-${Date.now()}`,
      ownerId,
      name,
      email,
      phone,
      dob,
      permanentAddress: address,
      unitId: unitId,
      propertyId,
      roomNumber,
      moveInDate,
      dueDate: 5,
      status: 'active',
      rent: parseInt(rent) || 0,
      idProofType,
      idNumber
    };
    db.saveResident(newRes);

    // Update unit count
    const unit = units.find(u => u.id === unitId);
    if (unit) {
      db.updateUnit({
        ...unit,
        currentOccupants: unit.currentOccupants + 1,
        status: (unit.currentOccupants + 1) >= unit.capacity ? RoomStatus.FULL : RoomStatus.PARTIAL
      });
    }

    setResidents(db.getResidents(ownerId));
    setUnits(db.getUnits(ownerId));
    setShowAdd(false);
    // Reset form
    setName(''); setEmail(''); setPhone(''); setDob(''); setAddress('');
    setPropertyId(''); setRoomNumber(''); setUnitId(''); setMoveInDate(''); setRent('');
    setIdProofType(''); setIdNumber('');
  };

  const getUnitStatusLabel = (u: Unit) => {
    if (u.status === RoomStatus.MAINTENANCE) return 'Maintenance';
    if (u.currentOccupants === 0) return 'Vacant';
    if (u.currentOccupants < u.capacity) return 'Partial';
    return 'Full';
  };

  const moveEligibleRooms = useMemo(() => {
    if (!selectedResidentForMove) return [];
    return units.filter(u => 
      u.propertyId === selectedResidentForMove.propertyId && 
      u.id !== selectedResidentForMove.unitId &&
      u.status !== RoomStatus.FULL && 
      u.status !== RoomStatus.MAINTENANCE
    );
  }, [selectedResidentForMove, units]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Residents</h1>
          <p className="text-slate-500 font-medium">Add placeholders so your residents can sign up.</p>
        </div>
        <button 
          onClick={handleTryAdd}
          className="bg-blue-600 text-white px-6 py-3 rounded-xl font-black uppercase tracking-widest text-xs hover:bg-blue-700 transition shadow-xl shadow-blue-100"
        >
          + Add Resident
        </button>
      </div>

      <UpgradeModal 
        isOpen={showUpgradeModal}
        onClose={() => setShowUpgradeModal(false)}
        onUpgrade={() => {
          setShowUpgradeModal(false);
          onUpgrade();
        }}
        limitType="residents"
        limitValue={plan.residents || 0}
      />

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 p-8">
        <div className="relative mb-10">
          <svg className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <input 
            type="text" 
            placeholder="Search email or name..." 
            className="w-full pl-14 pr-8 py-5 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:bg-white focus:border-blue-500 transition-all font-bold text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto">
          {residents.length === 0 ? (
            <div className="py-24 text-center">
