                    </td>
                    <td className="px-6 py-8 text-sm font-black text-slate-700">
                      RM {r.roomNumber || 'N/A'}
                    </td>
                    <td className="px-6 py-8">
                      <p className="text-base font-black text-slate-900">{formatCurrency(r.rent)}</p>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Due {r.dueDate}th</p>
