                     >
                       {val}-Share
                     </button>
                   ))}
                   <button
                     type="button"
                     onClick={() => setRoomType('custom')}
                     className={`py-3 rounded-xl text-xs font-black uppercase border transition-all ${
                       roomType === 'custom' 
                       ? 'bg-blue-600 text-white border-blue-600 shadow-lg shadow-blue-100' 
                       : 'bg-white text-slate-400 border-slate-200 hover:border-blue-300'
                     }`}
                   >
                     + Custom
                   </button>
                </div>
              </div>

              {roomType === 'custom' && (
                <div className="space-y-2 animate-in slide-in-from-top-2 duration-300">
                  <label className="text-[10px] font-black text-blue-600 uppercase tracking-widest ml-1">Enter Custom Share Number</label>
                  <input 
                    required 
                    value={customShare} 
                    onChange={(e) => setCustomShare(e.target.value)} 
                    type="number" 
                    placeholder="e.g., 6" 
                    className="w-full px-4 py-3 bg-blue-50/50 border border-blue-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-sm font-bold" 
                  />
                </div>
              )}

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Rent / Bed</label>
                  <div className="relative">
                    <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 font-bold">₹</span>
                    <input 
                      required 
                      value={rent} 
                      onChange={(e) => setRent(e.target.value)} 
                      type="number" 
                      placeholder="Rent amount" 
                      className="w-full pl-8 pr-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-sm font-bold" 
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Floor</label>
                  <input required value={floor} onChange={(e) => setFloor(e.target.value)} type="text" placeholder="e.g. 2nd" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-sm font-bold" />
                </div>
              </div>

              <div className="flex items-center gap-3 bg-slate-50 p-4 rounded-2xl border border-slate-100">
                <input 
                  type="checkbox" 
                  id="maintenance-mode"
                  checked={isMaintenance}
                  onChange={(e) => setIsMaintenance(e.target.checked)}
                  className="w-5 h-5 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                />
                <label htmlFor="maintenance-mode" className="text-xs font-bold text-slate-600 uppercase tracking-tight cursor-pointer">Set room under maintenance</label>
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Amenities</label>
                <div className="grid grid-cols-3 gap-y-4">
                  {Object.keys(amenities).map(amenity => (
                    <label key={amenity} className="flex items-center gap-3 cursor-pointer group">
                      <div className="relative inline-flex items-center">
                        <input 
                          type="checkbox" 
                          checked={amenities[amenity]} 
                          onChange={(e) => setAmenities({...amenities, [amenity]: e.target.checked})} 
                          className="sr-only peer" 
                        />
                        <div className="w-10 h-6 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600 shadow-sm border border-slate-100"></div>
                      </div>
                      <span className="text-[10px] font-black text-slate-500 group-hover:text-slate-900 transition-colors uppercase tracking-tight">{amenity}</span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Notes / Description</label>
                <textarea 
                  value={notes} 
                  onChange={(e) => setNotes(e.target.value)} 
                  rows={2} 
                  placeholder="Additional details about room location or specific features" 
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-sm font-bold resize-none" 
                />
              </div>

              <div className="flex gap-4 pt-4 sticky bottom-0 bg-white pb-2">
                <button type="button" onClick={() => { setShowAddModal(false); resetForm(); }} className="flex-1 py-4 border border-slate-100 text-slate-400 font-black uppercase tracking-widest text-xs rounded-xl hover:bg-slate-50 transition-all">Cancel</button>
                <button type="submit" className="flex-1 py-4 bg-blue-600 text-white font-black uppercase tracking-widest text-xs rounded-xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-100">
                   {editingUnitId ? 'Update Room Configuration' : 'Add Room Configuration'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Rooms;

import React, { useState, useMemo } from 'react';
import { db } from '../services/mockData';
import { formatCurrency } from '../constants';
import { Resident, PLAN_LIMITS, Property, Unit, RoomStatus } from '../types';
import UpgradeModal from './UpgradeModal';

interface ResidentsProps {
  ownerId: string;
  onUpgrade: () => void;
}

const Residents: React.FC<ResidentsProps> = ({ ownerId, onUpgrade }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [residents, setResidents] = useState<Resident[]>(db.getResidents(ownerId));
  const [properties] = useState<Property[]>(db.getProperties(ownerId));
  const [units, setUnits] = useState<Unit[]>(db.getUnits(ownerId));
  const [showAdd, setShowAdd] = useState(false);
  const [showUpgradeModal, setShowUpgradeModal] = useState(false);

  // Move Resident Modal State
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [selectedResidentForMove, setSelectedResidentForMove] = useState<Resident | null>(null);
  const [targetUnitId, setTargetUnitId] = useState('');

  // Detail Modal State
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedResidentForDetail, setSelectedResidentForDetail] = useState<Resident | null>(null);
  const [activeDetailTab, setActiveDetailTab] = useState<'info' | 'payments'>('info');

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [dob, setDob] = useState('');
  const [address, setAddress] = useState('');
  const [propertyId, setPropertyId] = useState('');
  const [roomNumber, setRoomNumber] = useState('');
  const [unitId, setUnitId] = useState('');
  const [moveInDate, setMoveInDate] = useState('');
  const [rent, setRent] = useState('');
  const [idProofType, setIdProofType] = useState('');
  const [idNumber, setIdNumber] = useState('');

  const user = db.getUsers().find((u: any) => u.id === ownerId);
  const plan = user?.plan ? PLAN_LIMITS[user.plan] : PLAN_LIMITS.FREE;

  // Filter units based on selected property
  const availableUnitsForProperty = useMemo(() => {
    if (!propertyId) return [];
    return units.filter(u => u.propertyId === propertyId);
  }, [propertyId, units]);

  // Generate payment history based on move-in date
  const paymentHistory = useMemo(() => {
    if (!selectedResidentForDetail) return [];
    const history = [];
    const moveIn = new Date(selectedResidentForDetail.moveInDate);
    const today = new Date();

    let current = new Date(today.getFullYear(), today.getMonth(), 1);
    const end = new Date(moveIn.getFullYear(), moveIn.getMonth(), 1);

    while (current >= end) {
      const monthLabel = current.toLocaleString('default', { month: 'long', year: 'numeric' });
      history.push({
        month: monthLabel,
        amount: selectedResidentForDetail.rent,
        status: current < today ? 'Paid' : 'Pending',
        date: current < today ? new Date(current.getFullYear(), current.getMonth(), selectedResidentForDetail.dueDate).toLocaleDateString() : '-'
      });
      current.setMonth(current.getMonth() - 1);
    }
    return history;
  }, [selectedResidentForDetail]);

  // Prorated Calculation Helpers
  const getProratedInfo = (resident: Resident, targetUnit: Unit) => {
    const now = new Date();
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
    const currentDay = now.getDate();
    const monthName = now.toLocaleString('default', { month: 'long' });

    const daysSpent = currentDay;
    const remainingDays = Math.max(0, daysInMonth - daysSpent);

    const oldDaily = resident.rent / daysInMonth;
    const newDaily = targetUnit.price / daysInMonth;

    const oldCost = oldDaily * daysSpent;
    const newCost = newDaily * remainingDays;
    const totalAdjusted = oldCost + newCost;

    return {
      daysInMonth,
      currentDay,
      daysSpent,
      remainingDays,
      oldCost,
      newCost,
      totalAdjusted,
      oldRent: resident.rent,
      newRent: targetUnit.price,
      monthName,
      isLeapYear: (now.getFullYear() % 4 === 0 && now.getFullYear() % 100 !== 0) || (now.getFullYear() % 400 === 0)
    };
  };

  const handleTryAdd = () => {
    if (plan.residents !== null && residents.length >= plan.residents) {
      setShowUpgradeModal(true);
      return;
    }
    setShowAdd(true);
  };

  const filteredResidents = residents.filter(r => 
    r.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    r.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDeleteResident = (id: string) => {
    if (window.confirm('Are you sure you want to remove this resident?')) {
      db.deleteResident(id);
      setResidents(db.getResidents(ownerId));
    }
  };

  const handleMoveResident = () => {
    if (!selectedResidentForMove || !targetUnitId) return;

    const targetUnit = units.find(u => u.id === targetUnitId);
    const oldUnitId = selectedResidentForMove.unitId;

    if (targetUnit) {
      const updatedTarget: Unit = {
        ...targetUnit,
        currentOccupants: targetUnit.currentOccupants + 1,
        status: (targetUnit.currentOccupants + 1) >= targetUnit.capacity ? RoomStatus.FULL : RoomStatus.PARTIAL
      };
      db.updateUnit(updatedTarget);

      const oldUnit = units.find(u => u.id === oldUnitId);
      if (oldUnit) {
        const updatedOld: Unit = {
          ...oldUnit,
          currentOccupants: Math.max(0, oldUnit.currentOccupants - 1),
          status: (oldUnit.currentOccupants - 1) === 0 ? RoomStatus.VACANT : RoomStatus.PARTIAL
        };
        db.updateUnit(updatedOld);
      }

      const updatedResident: Resident = {
        ...selectedResidentForMove,
        unitId: targetUnit.id,
        roomNumber: targetUnit.roomNumber,
        rent: targetUnit.price
      };
      db.updateResident(updatedResident);

      setResidents(db.getResidents(ownerId));
      setUnits(db.getUnits(ownerId));
      setShowMoveModal(false);
      setSelectedResidentForMove(null);
      setTargetUnitId('');
    }
  };

  const handleUnitChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const selectedUnitId = e.target.value;
    const unit = availableUnitsForProperty.find(u => u.id === selectedUnitId);
    if (unit) {
      setUnitId(unit.id);
      setRoomNumber(unit.roomNumber);
      if (unit.price) setRent(unit.price.toString());
    } else {
      setUnitId('');
      setRoomNumber('');
    }
  };

  const handleAddResident = (e: React.FormEvent) => {
    e.preventDefault();
    const newRes: Resident = {
      id: `RES-${Date.now()}`,
      ownerId,
      name,
      email,
      phone,
      dob,
      permanentAddress: address,
      unitId: unitId,
      propertyId,
      roomNumber,
      moveInDate,
      dueDate: 5,
      status: 'active',
      rent: parseInt(rent) || 0,
      idProofType,
      idNumber
    };
    db.saveResident(newRes);

    const unit = units.find(u => u.id === unitId);
    if (unit) {
      db.updateUnit({
        ...unit,
        currentOccupants: unit.currentOccupants + 1,
        status: (unit.currentOccupants + 1) >= unit.capacity ? RoomStatus.FULL : RoomStatus.PARTIAL
      });
    }

    setResidents(db.getResidents(ownerId));
    setUnits(db.getUnits(ownerId));
    setShowAdd(false);
    setName(''); setEmail(''); setPhone(''); setDob(''); setAddress('');
    setPropertyId(''); setRoomNumber(''); setUnitId(''); setMoveInDate(''); setRent('');
    setIdProofType(''); setIdNumber('');
  };

  const getUnitStatusLabel = (u: Unit) => {
    if (u.status === RoomStatus.MAINTENANCE) return 'Maintenance';
    if (u.currentOccupants === 0) return 'Vacant';
    if (u.currentOccupants < u.capacity) return 'Partial';
    return 'Full';
  };

  const moveEligibleRooms = useMemo(() => {
    if (!selectedResidentForMove) return [];
    return units.filter(u => 
      u.propertyId === selectedResidentForMove.propertyId && 
      u.id !== selectedResidentForMove.unitId &&
      u.status !== RoomStatus.MAINTENANCE &&
      u.currentOccupants < u.capacity 
    );
  }, [selectedResidentForMove, units]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Residents</h1>
          <p className="text-slate-500 font-medium">Manage and view detailed history of your tenants.</p>
        </div>
        <button 
          onClick={handleTryAdd}
          className="bg-blue-600 text-white px-6 py-3 rounded-xl font-black uppercase tracking-widest text-xs hover:bg-blue-700 transition shadow-xl shadow-blue-100"
        >
          + Add Resident
        </button>
      </div>

      <UpgradeModal 
        isOpen={showUpgradeModal}
        onClose={() => setShowUpgradeModal(false)}
        onUpgrade={() => {
          setShowUpgradeModal(false);
          onUpgrade();
        }}
        limitType="residents"
        limitValue={plan.residents || 0}
      />

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 p-8">
        <div className="relative mb-10">
          <svg className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <input 
            type="text" 
            placeholder="Search email or name..." 
            className="w-full pl-14 pr-8 py-5 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:bg-white focus:border-blue-500 transition-all font-bold text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto">
          {residents.length === 0 ? (
            <div className="py-24 text-center">
               <div className="w-20 h-20 bg-slate-50 rounded-full mx-auto flex items-center justify-center text-slate-200 mb-4">
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
               </div>
               <p className="text-slate-400 font-bold italic">No resident records found.</p>
            </div>
          ) : (
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-6 py-6">Profile</th>
                  <th className="px-6 py-6">Room</th>
                  <th className="px-6 py-6">Rent Info</th>
                  <th className="px-6 py-6">Status</th>
                  <th className="px-6 py-6 text-center">Move</th>
                  <th className="px-6 py-6 text-right">Manage</th>
                </tr>
