                       <select required value={idProofType} onChange={(e) => setIdProofType(e.target.value)} className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-sm font-bold appearance-none pr-10">
                         <option value="">Select ID type</option>
                         <option value="Aadhaar">Aadhaar Card</option>
                         <option value="PAN">PAN Card</option>
                         <option value="Voter ID">Voter ID</option>
                         <option value="Passport">Passport</option>
                         <option value="Driving License">Driving License</option>
                       </select>
                       <svg className="w-4 h-4 absolute right-3.5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                     </div>
                   </div>
                   <div className="space-y-2">
                     <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">ID Serial Number</label>
                     <input required value={idNumber} onChange={(e) => setIdNumber(e.target.value)} type="text" placeholder="ID proof number" className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-sm font-bold" />
                   </div>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Attachments</label>
                    <div className="w-full px-4 py-3 bg-slate-50 border border-dashed border-slate-200 rounded-xl flex items-center justify-between group cursor-pointer hover:border-blue-300 transition-colors">
                       <span className="text-xs font-bold text-slate-400">Choose Files <span className="text-slate-300 ml-2 font-medium">(No file chosen)</span></span>
                       <input type="file" className="hidden" id="tenant-files" />
                       <label htmlFor="tenant-files" className="text-[10px] font-black text-blue-600 cursor-pointer uppercase tracking-widest bg-white border border-blue-100 px-3 py-1.5 rounded-lg">Browse</label>
                    </div>
                 </div>
               </div>

               {/* Footer Buttons */}
               <div className="flex gap-4 pt-6 sticky bottom-0 bg-white pb-6">
                <button 
                  type="button" 
                  onClick={() => setShowAdd(false)}
                  className="flex-1 py-4 border border-slate-100 text-slate-400 font-black uppercase tracking-widest text-xs rounded-xl hover:bg-slate-50 transition-all"
                >
                  Discard
                </button>
                <button 
                  type="submit" 
                  className="flex-1 py-4 bg-blue-600 text-white font-black uppercase tracking-widest text-xs rounded-xl hover:bg-blue-700 transition-all shadow-xl shadow-blue-100"
                >
                  Complete Onboarding
                </button>
              </div>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Residents;

import React, { useState, useMemo } from 'react';
import { db } from '../services/mockData';
import { formatCurrency } from '../constants';
import { Resident, PLAN_LIMITS, Property, Unit, RoomStatus } from '../types';
import UpgradeModal from './UpgradeModal';

interface ResidentsProps {
  ownerId: string;
  onUpgrade: () => void;
}

const Residents: React.FC<ResidentsProps> = ({ ownerId, onUpgrade }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [residents, setResidents] = useState<Resident[]>(db.getResidents(ownerId));
  const [properties] = useState<Property[]>(db.getProperties(ownerId));
  const [units, setUnits] = useState<Unit[]>(db.getUnits(ownerId));
  const [showAdd, setShowAdd] = useState(false);
  const [showUpgradeModal, setShowUpgradeModal] = useState(false);

  // Move Resident Modal State
  const [showMoveModal, setShowMoveModal] = useState(false);
  const [selectedResidentForMove, setSelectedResidentForMove] = useState<Resident | null>(null);
  const [targetUnitId, setTargetUnitId] = useState('');

  // Detail Modal State
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [selectedResidentForDetail, setSelectedResidentForDetail] = useState<Resident | null>(null);
  const [activeDetailTab, setActiveDetailTab] = useState<'info' | 'payments'>('info');

  // Form State
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [dob, setDob] = useState('');
  const [address, setAddress] = useState('');
  const [propertyId, setPropertyId] = useState('');
  const [roomNumber, setRoomNumber] = useState('');
  const [unitId, setUnitId] = useState('');
  const [moveInDate, setMoveInDate] = useState('');
  const [dueDate, setDueDate] = useState('5');
  const [rent, setRent] = useState('');
  const [idProofType, setIdProofType] = useState('');
  const [idNumber, setIdNumber] = useState('');

  const user = db.getUsers().find((u: any) => u.id === ownerId);
  const plan = user?.plan ? PLAN_LIMITS[user.plan] : PLAN_LIMITS.FREE;

  // Filter units based on selected property
  const availableUnitsForProperty = useMemo(() => {
    if (!propertyId) return [];
    return units.filter(u => u.propertyId === propertyId);
  }, [propertyId, units]);

  // Generate payment history based on move-in date
  const paymentHistory = useMemo(() => {
    if (!selectedResidentForDetail) return [];
    const history = [];
    const moveIn = new Date(selectedResidentForDetail.moveInDate);
    const today = new Date();

    let current = new Date(today.getFullYear(), today.getMonth(), 1);
    const end = new Date(moveIn.getFullYear(), moveIn.getMonth(), 1);

    while (current >= end) {
      const monthLabel = current.toLocaleString('default', { month: 'long', year: 'numeric' });
      history.push({
        month: monthLabel,
        amount: selectedResidentForDetail.rent,
        status: current < today ? 'Paid' : 'Pending',
        date: current < today ? new Date(current.getFullYear(), current.getMonth(), selectedResidentForDetail.dueDate).toLocaleDateString() : '-'
      });
      current.setMonth(current.getMonth() - 1);
    }
    return history;
  }, [selectedResidentForDetail]);

  // Prorated Calculation Helpers
  const getProratedInfo = (resident: Resident, targetUnit: Unit) => {
    const now = new Date();
    const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
    const currentDay = now.getDate();
    const monthName = now.toLocaleString('default', { month: 'long' });

    const daysSpent = currentDay;
    const remainingDays = Math.max(0, daysInMonth - daysSpent);

    const oldDaily = resident.rent / daysInMonth;
    const newDaily = targetUnit.price / daysInMonth;

    const oldCost = oldDaily * daysSpent;
    const newCost = newDaily * remainingDays;
    const totalAdjusted = oldCost + newCost;

    return {
      daysInMonth,
      currentDay,
      daysSpent,
      remainingDays,
      oldCost,
      newCost,
      totalAdjusted,
      oldRent: resident.rent,
      newRent: targetUnit.price,
      monthName,
      isLeapYear: (now.getFullYear() % 4 === 0 && now.getFullYear() % 100 !== 0) || (now.getFullYear() % 400 === 0)
    };
  };

  const handleTryAdd = () => {
    if (plan.residents !== null && residents.length >= plan.residents) {
      setShowUpgradeModal(true);
      return;
    }
    setShowAdd(true);
  };

  const filteredResidents = residents.filter(r => 
    r.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    r.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDeleteResident = (id: string) => {
    if (window.confirm('Are you sure you want to remove this resident?')) {
      db.deleteResident(id);
      setResidents(db.getResidents(ownerId));
    }
  };

  const handleMoveResident = () => {
    if (!selectedResidentForMove || !targetUnitId) return;

    const targetUnit = units.find(u => u.id === targetUnitId);
    const oldUnitId = selectedResidentForMove.unitId;

    if (targetUnit) {
      const updatedTarget: Unit = {
        ...targetUnit,
        currentOccupants: targetUnit.currentOccupants + 1,
        status: (targetUnit.currentOccupants + 1) >= targetUnit.capacity ? RoomStatus.FULL : RoomStatus.PARTIAL
      };
      db.updateUnit(updatedTarget);

      const oldUnit = units.find(u => u.id === oldUnitId);
      if (oldUnit) {
        const updatedOld: Unit = {
          ...oldUnit,
          currentOccupants: Math.max(0, oldUnit.currentOccupants - 1),
          status: (oldUnit.currentOccupants - 1) === 0 ? RoomStatus.VACANT : RoomStatus.PARTIAL
        };
        db.updateUnit(updatedOld);
      }

      const updatedResident: Resident = {
        ...selectedResidentForMove,
        unitId: targetUnit.id,
        roomNumber: targetUnit.roomNumber,
        rent: targetUnit.price
      };
      db.updateResident(updatedResident);

      setResidents(db.getResidents(ownerId));
      setUnits(db.getUnits(ownerId));
      setShowMoveModal(false);
      setSelectedResidentForMove(null);
      setTargetUnitId('');
    }
  };

  const handleUnitChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const selectedUnitId = e.target.value;
    const unit = availableUnitsForProperty.find(u => u.id === selectedUnitId);
    if (unit) {
      setUnitId(unit.id);
      setRoomNumber(unit.roomNumber);
      if (unit.price) setRent(unit.price.toString());
    } else {
      setUnitId('');
      setRoomNumber('');
    }
  };

  const handleAddResident = (e: React.FormEvent) => {
    e.preventDefault();
    const newRes: Resident = {
      id: `RES-${Date.now()}`,
      ownerId,
      name,
      email,
      phone,
      dob,
      permanentAddress: address,
      unitId: unitId,
      propertyId,
      roomNumber,
      moveInDate,
      dueDate: parseInt(dueDate) || 5,
      status: 'active',
      rent: parseInt(rent) || 0,
      idProofType,
      idNumber
    };
    db.saveResident(newRes);

    const unit = units.find(u => u.id === unitId);
    if (unit) {
      db.updateUnit({
        ...unit,
        currentOccupants: unit.currentOccupants + 1,
        status: (unit.currentOccupants + 1) >= unit.capacity ? RoomStatus.FULL : RoomStatus.PARTIAL
      });
    }

    setResidents(db.getResidents(ownerId));
    setUnits(db.getUnits(ownerId));
    setShowAdd(false);
    setName(''); setEmail(''); setPhone(''); setDob(''); setAddress('');
    setPropertyId(''); setRoomNumber(''); setUnitId(''); setMoveInDate(''); setRent('');
    setDueDate('5'); setIdProofType(''); setIdNumber('');
  };

  const getUnitStatusLabel = (u: Unit) => {
    if (u.status === RoomStatus.MAINTENANCE) return 'Maintenance';
    if (u.currentOccupants === 0) return 'Vacant';
    if (u.currentOccupants < u.capacity) return 'Partial';
    return 'Full';
  };

  const moveEligibleRooms = useMemo(() => {
    if (!selectedResidentForMove) return [];
    return units.filter(u => 
      u.propertyId === selectedResidentForMove.propertyId && 
      u.id !== selectedResidentForMove.unitId &&
      u.status !== RoomStatus.MAINTENANCE &&
      u.currentOccupants < u.capacity 
    );
  }, [selectedResidentForMove, units]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Residents</h1>
          <p className="text-slate-500 font-medium">Manage and view detailed history of your tenants.</p>
        </div>
        <button 
          onClick={handleTryAdd}
          className="bg-blue-600 text-white px-6 py-3 rounded-xl font-black uppercase tracking-widest text-xs hover:bg-blue-700 transition shadow-xl shadow-blue-100"
        >
          + Add Resident
        </button>
      </div>

      <UpgradeModal 
        isOpen={showUpgradeModal}
        onClose={() => setShowUpgradeModal(false)}
        onUpgrade={() => {
          setShowUpgradeModal(false);
          onUpgrade();
        }}
        limitType="residents"
        limitValue={plan.residents || 0}
      />

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 p-8">
        <div className="relative mb-10">
          <svg className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          <input 
            type="text" 
            placeholder="Search email or name..." 
            className="w-full pl-14 pr-8 py-5 bg-slate-50/50 border border-slate-100 rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/5 focus:bg-white focus:border-blue-500 transition-all font-bold text-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto">
          {residents.length === 0 ? (
            <div className="py-24 text-center">
               <div className="w-20 h-20 bg-slate-50 rounded-full mx-auto flex items-center justify-center text-slate-200 mb-4">
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
               </div>
               <p className="text-slate-400 font-bold italic">No resident records found.</p>
            </div>
          ) : (
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-6 py-6">Profile</th>
                  <th className="px-6 py-6">Room</th>
                  <th className="px-6 py-6">Rent Info</th>
                  <th className="px-6 py-6">Status</th>
                  <th className="px-6 py-6 text-center">Move</th>
                  <th className="px-6 py-6 text-right">Manage</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredResidents.map((r) => (
                  <tr key={r.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-6 py-8 cursor-pointer" onClick={() => { setSelectedResidentForDetail(r); setShowDetailModal(true); setActiveDetailTab('info'); }}>
                      <div className="flex items-center gap-5">
                        <div className="w-12 h-12 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center font-black text-base group-hover:bg-blue-600 group-hover:text-white transition-all">{r.name[0]}</div>
                        <div>
                          <p className="font-black text-slate-900 leading-none mb-1 group-hover:text-blue-600 transition-colors">{r.name}</p>
                          <p className="text-xs font-bold text-slate-400 lowercase">{r.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-8 text-sm font-black text-slate-700">
                      RM {r.roomNumber || 'N/A'}
                    </td>
                    <td className="px-6 py-8">
                      <p className="text-base font-black text-slate-900">{formatCurrency(r.rent)}</p>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Due {r.dueDate}th</p>
                    </td>
                    <td className="px-6 py-8">
                      <span className="px-3 py-1.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl text-[9px] font-black uppercase tracking-widest">
                        ACTIVE
                      </span>
                    </td>
                    <td className="px-6 py-8 text-center">
                      <button 
                        onClick={(e) => { e.stopPropagation(); setSelectedResidentForMove(r); setShowMoveModal(true); }}
                        className="px-4 py-2 bg-blue-50 text-blue-600 border border-blue-100 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-blue-600 hover:text-white transition-all shadow-sm"
                      >
                        Relocate
                      </button>
                    </td>
                    <td className="px-6 py-8 text-right">
                       <button 
                        onClick={(e) => { e.stopPropagation(); handleDeleteResident(r.id); }}
                        className="p-3 text-slate-300 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all"
                       >
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                       </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {/* Resident Detail Modal */}
      {showDetailModal && selectedResidentForDetail && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setShowDetailModal(false)}></div>
          <div className="relative bg-white w-full max-w-2xl rounded-[3rem] shadow-2xl animate-in zoom-in duration-300 overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-10 pb-4 bg-slate-50/50 border-b border-slate-100 relative shrink-0">
               <button onClick={() => setShowDetailModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-600 transition">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
               </button>
               <div className="flex items-center gap-6">
                  <div className="w-20 h-20 rounded-[2rem] bg-blue-600 text-white flex items-center justify-center font-black text-3xl shadow-xl shadow-blue-100">
                    {selectedResidentForDetail.name[0]}
                  </div>
                  <div>
                    <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tight">{selectedResidentForDetail.name}</h2>
                    <p className="text-blue-600 text-sm font-black uppercase tracking-widest mt-1">Resident ID: {selectedResidentForDetail.id}</p>
                  </div>
               </div>

               {/* Tabs */}
               <div className="flex gap-8 mt-10">
                  <button 
                    onClick={() => setActiveDetailTab('info')}
                    className={`pb-4 text-xs font-black uppercase tracking-widest transition-all border-b-4 ${activeDetailTab === 'info' ? 'border-blue-600 text-slate-900' : 'border-transparent text-slate-400 hover:text-slate-600'}`}
                  >
                    Overview
                  </button>
                  <button 
                    onClick={() => setActiveDetailTab('payments')}
                    className={`pb-4 text-xs font-black uppercase tracking-widest transition-all border-b-4 ${activeDetailTab === 'payments' ? 'border-blue-600 text-slate-900' : 'border-transparent text-slate-400 hover:text-slate-600'}`}
                  >
                    Payment History
                  </button>
               </div>
            </div>

            <div className="flex-1 overflow-y-auto p-10">
              {activeDetailTab === 'info' ? (
                <div className="space-y-10 animate-in fade-in duration-300">
                   <div className="grid grid-cols-2 gap-8">
                      <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Move-in Date</p>
                        <p className="font-bold text-slate-900">{new Date(selectedResidentForDetail.moveInDate).toLocaleDateString('en-IN', { dateStyle: 'long' })}</p>
                      </div>
                      <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Current Room</p>
                        <p className="font-bold text-slate-900">RM {selectedResidentForDetail.roomNumber}</p>
                      </div>
                      <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Monthly Rent</p>
