import React from 'react';
import { UserRole, Resident } from '../types';
import { formatCurrency, Icons } from '../constants';
import { db } from '../services/mockData';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';

const chartData = [
  { name: 'Jan', revenue: 4000 },
  { name: 'Feb', revenue: 3000 },
  { name: 'Mar', revenue: 2000 },
  { name: 'Apr', revenue: 2780 },
  { name: 'May', revenue: 1890 },
  { name: 'Jun', revenue: 2390 },
];

const StatCard = ({ title, value, trend, isCurrency, trendType }: any) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
    <div className="flex justify-between items-start mb-4">
      <h3 className="text-sm font-medium text-slate-500">{title}</h3>
      <span className={`flex items-center gap-1 text-xs font-bold px-2 py-1 rounded-full ${
        trendType === 'up' ? 'text-emerald-600 bg-emerald-50' : 'text-rose-600 bg-rose-50'
      }`}>
        {trendType === 'up' ? '↑' : '↓'} {trend}%
      </span>
    </div>
    <p className="text-2xl font-bold text-slate-900">
      {isCurrency ? formatCurrency(value) : value}
    </p>
    <div className="mt-4 h-12 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={chartData}>
          <Area type="monotone" dataKey="revenue" stroke={trendType === 'up' ? '#10B981' : '#EF4444'} fillOpacity={0.1} fill={trendType === 'up' ? '#10B981' : '#EF4444'} />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  </div>
);

interface DashboardProps {
  role: UserRole;
  ownerId: string;
  onAddProperty: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ role, ownerId, onAddProperty }) => {
  const properties = db.getProperties(ownerId);
  const residents = db.getResidents(ownerId);
  const totalRevenue = properties.reduce((acc, p) => acc + (p.revenue || 0), 0);

  // Calculate upcoming dues (within 3 days)
  const upcomingDues = residents.filter(res => {
    const today = new Date();
    const currentDay = today.getDate();
    const daysInMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();

    let diff = res.dueDate - currentDay;

    // Handle month wrap-around (e.g., today is 29th, due date is 2nd)
    if (diff < 0) {
      diff = (daysInMonth - currentDay) + res.dueDate;
    }

    return diff >= 0 && diff <= 3;
  });

  if (properties.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-4">
        <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center text-blue-600">
           <Icons.Property />
        </div>
        <h2 className="text-2xl font-black text-slate-900">No Properties Found</h2>
        <p className="text-slate-500 max-w-sm">Start by adding your first hostel property to see analytics here.</p>
        <button 
          onClick={onAddProperty}
          className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-blue-700 transition shadow-lg shadow-blue-100"
        >
          + Add My First Property
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900 uppercase tracking-tight">Hostel Insights</h1>
          <p className="text-slate-500 font-medium italic">Live metrics and proactive billing alerts.</p>
        </div>
      </div>

      {upcomingDues.length > 0 && (
        <div className="bg-orange-50 border border-orange-100 p-6 rounded-[2rem] animate-in fade-in slide-in-from-top-4 duration-500">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-8 h-8 bg-orange-200 text-orange-700 rounded-full flex items-center justify-center">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            </div>
            <h2 className="text-xs font-black text-orange-700 uppercase tracking-widest">Upcoming Billing (Next 3 Days)</h2>
          </div>
          <div className="flex flex-wrap gap-3">
             {upcomingDues.map(res => (
               <div key={res.id} className="bg-white px-4 py-3 rounded-2xl border border-orange-200 shadow-sm flex items-center gap-4">
                 <div>
                   <p className="text-xs font-black text-slate-900">{res.name}</p>
                   <p className="text-[10px] text-slate-400 font-bold">RM {res.roomNumber} • Due {res.dueDate}th</p>
                 </div>
                 <div className="text-right">
                   <p className="text-xs font-black text-orange-600">{formatCurrency(res.rent)}</p>
                 </div>
               </div>
             ))}
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Monthly Revenue" value={totalRevenue} trend={12} isCurrency trendType="up" />
        <StatCard title="Properties" value={properties.length} trend={2} trendType="up" />
        <StatCard title="Total Residents" value={residents.length} trend={8} trendType="up" />
        <StatCard title="Billing Alerts" value={upcomingDues.length} trend={0} trendType="up" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
          <h3 className="font-black text-slate-900 mb-8 uppercase text-[10px] tracking-widest">Revenue Forecast (6 Months)</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
