        </div>

        <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col">
          <h3 className="font-black text-slate-900 mb-8 uppercase text-[10px] tracking-widest">Property Distribution</h3>
          <div className="flex-1 flex flex-col justify-center gap-6">
             {properties.slice(0, 4).map(p => (
               <div key={p.id} className="space-y-2">
                 <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-tight">
                    <span className="text-slate-500">{p.name}</span>
                    <span className="text-blue-600">{formatCurrency(p.revenue)}</span>
                 </div>
                 <div className="h-2 w-full bg-slate-50 rounded-full overflow-hidden border border-slate-100">
                    <div 
                      className="h-full bg-blue-600 rounded-full" 
                      style={{ width: `${Math.min(100, (p.revenue / totalRevenue) * 100)}%` }}
                    ></div>
                 </div>
               </div>
             ))}
             {properties.length === 0 && (
               <p className="text-slate-400 text-sm italic text-center">No property data available.</p>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

