import React, { useMemo } from 'react';
import { formatCurrency, Icons } from '../constants';
import { db } from '../services/mockData';

interface ResidentAppProps {
  residentId: string;
}

const ResidentApp: React.FC<ResidentAppProps> = ({ residentId }) => {
  // Find resident data from db
  const residents = db.getResidents();
  const currentResident = residents.find(r => r.id === residentId || r.email === residentId);

  // Calculate if due date is within 3 days
  const billingStatus = useMemo(() => {
    if (!currentResident) return null;

    const today = new Date();
    const currentDay = today.getDate();
    const daysInMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();

    let diff = currentResident.dueDate - currentDay;

    // Handle month wrap-around
    if (diff < 0) {
      diff = (daysInMonth - currentDay) + currentResident.dueDate;
    }

    return {
      daysRemaining: diff,
      isUpcoming: diff >= 0 && diff <= 3
    };
  }, [currentResident]);

  if (!currentResident) {
    return (
      <div className="p-12 text-center">
         <h1 className="text-2xl font-bold text-slate-900">Access Denied</h1>
         <p className="text-slate-500">Your resident profile could not be found. Please contact your property owner.</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 max-w-2xl mx-auto animate-in fade-in duration-500">
      {/* Due Date Notification Banner */}
      {billingStatus?.isUpcoming && (
        <div className="bg-orange-500 text-white rounded-[2rem] p-8 shadow-xl shadow-orange-100 flex flex-col sm:flex-row items-center justify-between gap-6 border-b-4 border-orange-700 animate-in slide-in-from-top-4 duration-500">
           <div className="flex items-center gap-5">
              <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-sm border border-white/30">
                 <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              </div>
              <div>
                <h3 className="text-lg font-black uppercase tracking-tight">Payment Approaching</h3>
                <p className="text-orange-50 text-[10px] font-black uppercase tracking-widest opacity-80">
                  {billingStatus.daysRemaining === 0 ? "Due Today" : `Due in ${billingStatus.daysRemaining} days`} • {formatCurrency(currentResident.rent)}
                </p>
              </div>
           </div>
           <button className="bg-white text-orange-600 px-6 py-3 rounded-xl font-black uppercase tracking-widest text-[10px] shadow-lg hover:bg-orange-50 transition active:scale-95">
              Pay Now
           </button>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 p-10">
        <div className="flex items-center gap-6 mb-10">
          <div className="w-20 h-20 rounded-3xl bg-blue-600 flex items-center justify-center text-white text-3xl font-black shadow-xl shadow-blue-100">
             {currentResident.name[0]}
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 leading-tight">Hello, {currentResident.name.split(' ')[0]}</h1>
            <p className="text-sm font-bold text-slate-400 uppercase tracking-widest mt-1">Resident Portal • RM {currentResident.roomNumber}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
          <div className="bg-blue-50/50 p-8 rounded-[2rem] border border-blue-100">
            <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-1">Monthly Rent</p>
            <p className="text-4xl font-black text-blue-900">{formatCurrency(currentResident.rent)}</p>
          </div>
          <div className="bg-orange-50/50 p-8 rounded-[2rem] border border-orange-100">
            <p className="text-[10px] font-black text-orange-600 uppercase tracking-widest mb-1">Due Date</p>
            <p className="text-4xl font-black text-orange-900">{currentResident.dueDate}th</p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 p-10">
        <h3 className="font-black text-slate-900 uppercase tracking-widest text-xs mb-8">Action Center</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
           <button className="flex flex-col items-center justify-center gap-3 p-8 bg-blue-600 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs hover:bg-blue-700 transition shadow-xl shadow-blue-100 hover:-translate-y-1">
              <div className="bg-white/20 p-3 rounded-xl mb-1">
                <Icons.Payments />
              </div>
              Pay Rent Now
           </button>
           <button className="flex flex-col items-center justify-center gap-3 p-8 bg-white border border-slate-100 text-slate-600 rounded-[2rem] font-black uppercase tracking-widest text-xs hover:bg-slate-50 transition hover:-translate-y-1">
              <div className="bg-slate-100 p-3 rounded-xl mb-1">
                <Icons.Complaints />
              </div>
              Raise Ticket
           </button>
        </div>
      </div>
    </div>
  );
};

